INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('COPYWRITING: La formule AIDA (Attention, Interet, Desir, Action) reste la plus efficace pour les pages de vente en 2026.', 'AIDA = formule #1 pages de vente', 'content', 'best_practice', 0.92, 'massive_boost_15', 'system'),
('COPYWRITING: Les titres avec des chiffres impairs (7, 9, 11) obtiennent 20% plus de clics que les chiffres pairs.', 'Chiffres impairs titres = +20% clics', 'content', 'insight', 0.80, 'massive_boost_15', 'system'),
('COPYWRITING: Le mot "vous" dans un titre augmente le taux de clic de 31%. Parler au lecteur, pas de soi.', 'Vous dans titre = +31% clics', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('COPYWRITING: Les bullet points augmentent la lisibilite de 47% et le temps sur page de 23%.', 'Bullet points = +47% lisibilite +23% temps', 'content', 'insight', 0.85, 'massive_boost_15', 'system'),
('COPYWRITING: La formule PAS (Probleme, Agitation, Solution) est ideale pour les emails de vente et les posts LinkedIn.', 'PAS = ideal emails vente + LinkedIn', 'content', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('COPYWRITING: Les power words (secret, exclusif, gratuit, nouveau, maintenant) augmentent les conversions de 12-25%.', 'Power words = +12-25% conversions', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('COPYWRITING: Un seul CTA par page/email. Plusieurs CTAs reduisent les conversions de 42% (paradoxe du choix).', '1 CTA par page. Multi-CTA = -42%', 'content', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('COPYWRITING: Les temoignages avec photo + prenom + metier convertissent 3x plus que les temoignages anonymes.', 'Temoignage photo+nom+metier = 3x conversion', 'content', 'insight', 0.88, 'massive_boost_15', 'system'),
('COPYWRITING: Les garanties satisfait ou rembourse augmentent les ventes de 20% et les remboursements reels < 3%.', 'Garantie = +20% ventes, < 3% remboursements', 'commercial', 'insight', 0.85, 'massive_boost_15', 'system'),
('COPYWRITING: Le PS dans un email est lu par 79% des lecteurs. Placer le CTA secondaire dans le PS.', 'PS email = 79% lecture. CTA secondaire ici', 'email', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('PRICING: L ancrage prix (montrer le prix barre) augmente la valeur percue de 40%. Toujours montrer l economie.', 'Ancrage prix barre = +40% valeur percue', 'commercial', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('PRICING: Les prix en .99 fonctionnent pour le B2C mais reduisent la credibilite en B2B. Utiliser des prix ronds en B2B.', '.99 = B2C ok, B2B prix ronds', 'commercial', 'insight', 0.82, 'massive_boost_15', 'system'),
('PRICING: La regle des 3 options (bon/meilleur/premium) dirige 60% des choix vers l option du milieu.', '3 options = 60% choisissent milieu', 'commercial', 'insight', 0.88, 'massive_boost_15', 'system'),
('PRICING: Afficher le prix mensuel meme pour un paiement annuel (ex: 8€/mois facture 96€/an) augmente la conversion de 30%.', 'Prix mensuel pour annuel = +30% conversion', 'commercial', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('PRICING: Les plans gratuits avec limitations strategiques convertissent 3-5% des users en payants dans les 30 premiers jours.', 'Freemium = 3-5% conversion J30', 'ceo', 'insight', 0.85, 'massive_boost_15', 'system'),
('LINKEDIN: Les posts avec 1300-1500 caracteres obtiennent le plus d engagement. Ni trop court ni trop long.', 'LinkedIn ideal = 1300-1500 caracteres', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('LINKEDIN: Publier entre 7h30 et 8h30 en semaine maximise la portee. Le mardi et jeudi sont les meilleurs jours.', 'LinkedIn: 7h30-8h30 mardi/jeudi optimal', 'content', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('LINKEDIN: Les posts qui commencent par une statistique surprenante ont 2x plus de clics sur Voir plus.', 'LinkedIn stat surprenante debut = 2x Voir plus', 'content', 'insight', 0.82, 'massive_boost_15', 'system'),
('LINKEDIN: Le personal branding genere 7x plus de leads que le branding entreprise sur LinkedIn.', 'Personal branding LinkedIn = 7x leads vs corporate', 'content', 'insight', 0.85, 'massive_boost_15', 'system'),
('LINKEDIN: Les documents PDF (carrousels LinkedIn) ont 3x plus de portee que les posts texte simples.', 'PDF carrousel LinkedIn = 3x portee vs texte', 'content', 'insight', 0.88, 'massive_boost_15', 'system'),
('LINKEDIN: Commenter les posts des autres (commentaires de valeur) augmente sa propre visibilite de 200%.', 'Commenter valeur LinkedIn = +200% visibilite', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('LINKEDIN: L algorithme LinkedIn favorise les conversations. Un post avec 10+ commentaires gagne 4x plus de portee.', 'LinkedIn 10+ commentaires = 4x portee', 'content', 'insight', 0.88, 'massive_boost_15', 'system'),
('TIKTOK: Les videos entre 21-34 secondes ont le meilleur ratio completion rate. Ni trop court ni trop long.', 'TikTok ideal = 21-34 secondes', 'tiktok_comments', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('TIKTOK: Le hook des 3 premieres secondes determine 90% de la retention. Utiliser un pattern interrupt visuel.', 'TikTok hook 3s = 90% retention', 'tiktok_comments', 'best_practice', 0.92, 'massive_boost_15', 'system'),
('TIKTOK: Les videos avec sous-titres ont 40% plus de completion car 80% regardent sans le son.', 'Sous-titres TikTok = +40% completion (80% sans son)', 'tiktok_comments', 'insight', 0.88, 'massive_boost_15', 'system'),
('TIKTOK: Le meilleur moment pour poster: 7h-9h et 19h-23h. Les weekends ont plus de temps de visionnage.', 'TikTok: 7-9h et 19-23h, weekends = plus de watch time', 'tiktok_comments', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('TIKTOK: Les duets et stitches avec des createurs populaires augmentent la portee de 5-10x.', 'Duet/stitch populaires TikTok = 5-10x portee', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('TIKTOK: Le storytelling en 3 actes (probleme → tension → resolution) est le format le plus viral.', 'Storytelling 3 actes TikTok = format viral', 'tiktok_comments', 'insight', 0.88, 'massive_boost_15', 'system'),
('INSTAGRAM: Les Reels de 15-30 secondes avec musique trending obtiennent 3x plus de portee que les Reels longs.', 'Reels 15-30s + trending music = 3x portee', 'content', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('INSTAGRAM: Les stories avec polls/quizz ont 40% plus d interactions que les stories passives.', 'Stories polls/quizz = +40% interactions', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('INSTAGRAM: Publier 1 Reel par jour est la strategie #1 pour la croissance en 2026.', '1 Reel/jour = strategie #1 croissance IG 2026', 'content', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('INSTAGRAM: Les hashtags de niche (10K-100K posts) performent mieux que les hashtags massifs (1M+ posts).', 'Hashtags niche 10K-100K > massifs 1M+', 'content', 'insight', 0.85, 'massive_boost_15', 'system'),
('INSTAGRAM: Le ratio ideal: 60% Reels, 20% carrousels, 15% stories, 5% photos. Les Reels drive la decouverte.', 'IG ratio: 60% Reels 20% carrousels 15% stories 5% photos', 'content', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('SEO: Les articles de 2000-2500 mots rankent en moyenne en position 1-3 sur Google. La profondeur est recompensee.', 'SEO 2000-2500 mots = top 3 Google', 'seo', 'insight', 0.88, 'massive_boost_15', 'system'),
('SEO: Les Core Web Vitals (LCP < 2.5s, FID < 100ms, CLS < 0.1) sont un facteur de ranking confirme.', 'Core Web Vitals = facteur ranking Google', 'seo', 'best_practice', 0.92, 'massive_boost_15', 'system'),
('SEO: Les backlinks de sites .edu et .gov ont 3x plus de poids que les backlinks de sites commerciaux.', 'Backlinks .edu/.gov = 3x poids', 'seo', 'insight', 0.82, 'massive_boost_15', 'system'),
('SEO: Le maillage interne (liens entre articles) augmente le temps sur site de 40% et aide le crawl Google.', 'Maillage interne = +40% temps site + crawl', 'seo', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('SEO: Les pages avec schema markup (structured data) ont 25% plus de clics dans les SERP.', 'Schema markup = +25% CTR SERP', 'seo', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('SEO: La cannibalisation SEO (2 pages ciblant le meme mot-cle) divise le ranking. Fusionner les pages.', 'Cannibalisation SEO = fusionner pages', 'seo', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('SEO: Les recherches vocales (20% des recherches mobile) utilisent des phrases completes. Optimiser pour les questions.', 'Recherche vocale 20% mobile = optimiser questions', 'seo', 'insight', 0.82, 'massive_boost_15', 'system'),
('ADS: Le ROAS minimum viable: 3x pour e-commerce, 5x pour services, 2x pour lead generation.', 'ROAS minimum: 3x ecom, 5x services, 2x leadgen', 'ads', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('ADS: Les creatives video de 6-15 secondes convertissent le mieux sur Meta Ads. Format 9:16 obligatoire.', 'Meta Ads video 6-15s format 9:16 = meilleur', 'ads', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('ADS: Le retargeting des visiteurs qui ont vu 75%+ d une video a un taux de conversion 8x superieur au cold.', 'Retargeting video 75%+ = 8x conversion vs cold', 'ads', 'insight', 0.85, 'massive_boost_15', 'system'),
('ADS: Les audiences lookalike a 1% sont les plus precises. Au-dela de 3% la qualite diminue significativement.', 'Lookalike 1% = meilleur, > 3% = qualite baisse', 'ads', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('ADS: Le CBO (Campaign Budget Optimization) de Meta performe mieux que le budget par ad set pour les campagnes matures.', 'CBO Meta > budget par ad set (campagnes matures)', 'ads', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('ADS: Les UGC ads (User Generated Content) ont un CTR 4x superieur aux creatives pro sur Meta.', 'UGC ads = 4x CTR vs creatives pro Meta', 'ads', 'insight', 0.88, 'massive_boost_15', 'system'),
('ADS: Le frequency cap optimal: 3-5 expositions par semaine. Au-dela c est du gaspillage et de l agacement.', 'Frequency cap: 3-5/semaine optimal', 'ads', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('ADS: Les heures creuses (22h-6h) ont un CPM 40% moins cher. Ideal pour les campagnes de notoriete.', 'Heures creuses 22h-6h = -40% CPM notoriete', 'ads', 'insight', 0.80, 'massive_boost_15', 'system'),
('EMAIL: Le meilleur jour pour les emails B2B: mardi. Pour B2C: jeudi et samedi matin.', 'Email B2B mardi, B2C jeudi/samedi matin', 'email', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('EMAIL: La segmentation par comportement (clics, achats) genere 760% plus de revenus que les emails generiques.', 'Segmentation comportement = +760% revenus', 'email', 'insight', 0.88, 'massive_boost_15', 'system'),
('EMAIL: Les emails avec preheader personnalise ont 7% plus d ouvertures. Ne jamais laisser le preheader vide.', 'Preheader personnalise = +7% ouvertures', 'email', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('EMAIL: La sequence de bienvenue (3-5 emails sur 10 jours) est la plus rentable: 320% plus de revenus que les one-shot.', 'Sequence bienvenue = +320% revenus vs one-shot', 'email', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('EMAIL: Le taux de delivrabilite doit etre > 95%. En dessous, verifier le SPF/DKIM/DMARC et nettoyer la liste.', 'Delivrabilite > 95%, sinon SPF/DKIM/DMARC + nettoyage', 'email', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('EMAIL: Les emails transactionnels (confirmation, facture) ont 8x plus d ouvertures. Y inclure un CTA marketing subtil.', 'Email transactionnel = 8x ouvertures. CTA marketing subtil', 'email', 'insight', 0.82, 'massive_boost_15', 'system'),
('WHATSAPP: Le taux de reponse WhatsApp Business est de 45-60% (vs 2-5% email). C est le canal le plus engageant.', 'WhatsApp = 45-60% reponse vs 2-5% email', 'whatsapp', 'insight', 0.90, 'massive_boost_15', 'system'),
('WHATSAPP: Les messages avec rich media (image + texte) ont 2x plus de clics que le texte seul.', 'WhatsApp rich media = 2x clics vs texte', 'whatsapp', 'insight', 0.85, 'massive_boost_15', 'system'),
('WHATSAPP: Ne jamais envoyer plus de 2 messages promotionnels par semaine. Au-dela le taux de blocage explose.', 'WhatsApp max 2 promos/semaine sinon blocage', 'whatsapp', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('WHATSAPP: Les catalogues produits WhatsApp augmentent les ventes de 30% pour les commerces locaux.', 'Catalogue WhatsApp = +30% ventes local', 'whatsapp', 'insight', 0.82, 'massive_boost_15', 'system'),
('DM: Le premier DM doit etre une question ouverte, jamais un pitch. Le taux de reponse passe de 5% a 35%.', 'Premier DM = question ouverte. 5% → 35% reponse', 'dm_instagram', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('DM: Les DMs envoyes dans les 5 minutes apres un follow ont 3x plus de chances d obtenir une reponse.', 'DM < 5 min apres follow = 3x reponse', 'dm_instagram', 'insight', 0.85, 'massive_boost_15', 'system'),
('DM: Les messages vocaux en DM ont un taux de reponse 2x superieur aux messages texte (plus personnel).', 'DM vocal = 2x reponse vs texte', 'dm_instagram', 'insight', 0.82, 'massive_boost_15', 'system'),
('DM: Ne jamais copier-coller le meme DM. L algorithme Instagram detecte les messages identiques et penalise le compte.', 'DM copie-colle = penalite IG. Toujours personnaliser', 'dm_instagram', 'best_practice', 0.92, 'massive_boost_15', 'system'),
('DM: La methode SPIN pour les DM B2B: Situation → Probleme → Implication → Need-payoff.', 'DM B2B methode SPIN: S→P→I→N', 'dm_instagram', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('CHATBOT: Le temps de reponse ideal d un chatbot: < 3 secondes. Au-dela l utilisateur perd patience.', 'Chatbot reponse < 3s ideal', 'chatbot', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('CHATBOT: Les chatbots qui proposent des boutons de reponse rapide ont 40% plus d engagement que le texte libre seul.', 'Chatbot boutons rapides = +40% engagement', 'chatbot', 'insight', 0.85, 'massive_boost_15', 'system'),
('CHATBOT: Le ton conversationnel (pas robot) augmente la satisfaction de 35%. Utiliser des contractions et de l humour leger.', 'Chatbot ton conversationnel = +35% satisfaction', 'chatbot', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('CHATBOT: Les chatbots qui collectent l email avant de repondre perdent 60% des visiteurs. D abord aider, ensuite collecter.', 'Chatbot: aider d abord, email ensuite. Sinon -60%', 'chatbot', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('GMAPS: Les fiches Google avec 50+ avis et 4.5+ etoiles apparaissent dans le pack local 3x plus souvent.', 'GMB 50+ avis 4.5+ = 3x pack local', 'gmaps', 'insight', 0.88, 'massive_boost_15', 'system'),
('GMAPS: Publier 1 Google Post par semaine augmente les clics vers le site de 25%.', 'Google Post hebdo = +25% clics site', 'gmaps', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('GMAPS: Les questions-reponses sur la fiche Google sont indexees par le moteur de recherche. Les pre-remplir soi-meme.', 'Q&A GMB indexees par Google. Pre-remplir', 'gmaps', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('GMAPS: Les photos ajoutees par le proprietaire sont vues 2x plus que celles des clients. En ajouter 5+ par mois.', 'Photos proprietaire GMB = 2x vues. 5+/mois', 'gmaps', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('RETENTION: Le Net Revenue Retention (NRR) > 120% est le signe d un produit SaaS excellent. KeiroAI doit viser 130%+.', 'NRR > 120% = excellent SaaS. Viser 130%+', 'ceo', 'insight', 0.88, 'massive_boost_15', 'system'),
('RETENTION: L email de reengagement (nous vous manquons) a un taux de reconversion de 5-10% si envoye J+7 apres inactivite.', 'Email reengagement J+7 = 5-10% reconversion', 'retention', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('RETENTION: Les users qui completent l onboarding ont 5x moins de churn. L onboarding est le moment le plus critique.', 'Onboarding complet = 5x moins churn', 'onboarding', 'insight', 0.92, 'massive_boost_15', 'system'),
('RETENTION: Le cohort analysis est le meilleur outil pour detecter les problemes de retention. Analyser par semaine d inscription.', 'Cohort analysis = outil #1 detection retention', 'ceo', 'best_practice', 0.85, 'massive_boost_15', 'system'),
('RETENTION: Les clients qui utilisent 3+ features ont 85% de retention a 12 mois. Pousser l adoption multi-features.', '3+ features = 85% retention 12 mois', 'retention', 'insight', 0.88, 'massive_boost_15', 'system'),
('GROWTH: Le viral coefficient K > 1 signifie croissance exponentielle. Chaque user invite plus d 1 nouveau user.', 'K factor > 1 = croissance exponentielle', 'ceo', 'insight', 0.88, 'massive_boost_15', 'system'),
('GROWTH: Le referral program optimal offre une recompense aux 2 parties (parrain + filleul). +60% de participation vs one-sided.', 'Referral bilateral = +60% participation', 'marketing', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('GROWTH: Les product-led growth (PLG) companies convertissent 2x mieux car le produit fait le travail de vente.', 'PLG = 2x meilleure conversion', 'ceo', 'insight', 0.85, 'massive_boost_15', 'system'),
('GROWTH: Le CAC payback period optimal pour un SaaS: < 12 mois. Au-dela le modele n est pas soutenable.', 'CAC payback < 12 mois SaaS', 'ceo', 'best_practice', 0.90, 'massive_boost_15', 'system'),
('GROWTH: L effet reseau (network effect) est le moat le plus puissant. Chaque user ajoute de la valeur pour tous les autres.', 'Network effect = moat le plus puissant', 'ceo', 'insight', 0.88, 'massive_boost_15', 'system'),
('BRANDING: La coherence visuelle (memes couleurs, typographies, tons) augmente la reconnaissance de marque de 80%.', 'Coherence visuelle = +80% reconnaissance marque', 'marketing', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('BRANDING: Les marques qui publient du behind-the-scenes ont 33% plus d engagement. L authenticite est le nouveau premium.', 'Behind-the-scenes = +33% engagement', 'content', 'insight', 0.82, 'massive_boost_15', 'system'),
('BRANDING: Le brand voice document doit couvrir: ton, vocabulaire, emojis, interdits. Tous les agents doivent le respecter.', 'Brand voice: ton + vocab + emojis + interdits', 'marketing', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('UX: Le temps de chargement ideal d une page: < 2 secondes. Chaque seconde supplementaire perd 7% de conversions.', 'Page < 2s. +1s = -7% conversions', 'seo', 'insight', 0.90, 'massive_boost_15', 'system'),
('UX: Le formulaire ideal a 3-5 champs. Chaque champ supplementaire reduit les completions de 10%.', 'Formulaire 3-5 champs. +1 champ = -10% completions', 'commercial', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('UX: Le bouton CTA doit etre visible sans scroller (above the fold). Les CTA below-the-fold perdent 40% de clics.', 'CTA above the fold. Below = -40% clics', 'commercial', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('UX: Les couleurs de CTA contrastantes (orange, vert vif) augmentent les clics de 21% vs les couleurs neutres.', 'CTA couleur contrastante = +21% clics', 'commercial', 'insight', 0.82, 'massive_boost_15', 'system'),
('ANALYTICS: Le bounce rate moyen acceptable: 40-60% pour un blog, 20-40% pour un e-commerce, 10-30% pour un SaaS.', 'Bounce rate: 40-60% blog, 20-40% ecom, 10-30% SaaS', 'ceo', 'insight', 0.85, 'massive_boost_15', 'system'),
('ANALYTICS: Les micro-conversions (signup newsletter, telechargement guide) predisent les macro-conversions (achat) a 70%.', 'Micro-conversions predisent macro a 70%', 'ceo', 'insight', 0.82, 'massive_boost_15', 'system'),
('ANALYTICS: L attribution multi-touch (vs last-click) montre que les canaux top-of-funnel sont sous-evalues de 35%.', 'Attribution multi-touch: top-funnel sous-evalue 35%', 'ceo', 'insight', 0.82, 'massive_boost_15', 'system'),
('CONVERSION: L urgence reelle (stock limite, offre temporaire) augmente les conversions de 332%. Ne jamais fausser l urgence.', 'Urgence reelle = +332% conversion. Jamais fake', 'commercial', 'insight', 0.85, 'massive_boost_15', 'system'),
('CONVERSION: Le social proof (X clients satisfaits) augmente la confiance de 63%. Mettre les chiffres reels.', 'Social proof chiffres reels = +63% confiance', 'commercial', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('CONVERSION: Les popups de sortie (exit intent) recuperent 10-15% des visiteurs qui allaient partir.', 'Exit intent popup = 10-15% recuperation', 'commercial', 'insight', 0.82, 'massive_boost_15', 'system'),
('CONVERSION: La page de destination (landing page) dediee convertit 5x mieux que rediriger vers la homepage.', 'Landing page dediee = 5x vs homepage', 'commercial', 'insight', 0.90, 'massive_boost_15', 'system'),
('CONVERSION: Les videos explicatives sur la landing page augmentent les conversions de 80%.', 'Video explicative landing = +80% conversions', 'commercial', 'insight', 0.85, 'massive_boost_15', 'system'),
('AUTOMATION: Le lead scoring automatique (comportement + profil) permet de prioriser les 20% de leads qui generent 80% du CA.', 'Lead scoring auto = prioriser 20% leads → 80% CA', 'commercial', 'best_practice', 0.88, 'massive_boost_15', 'system'),
('AUTOMATION: Les workflows automatises (si X alors Y) reduisent le temps commercial de 40% et les oublis de suivi a 0%.', 'Workflows auto = -40% temps commercial, 0% oublis', 'commercial', 'insight', 0.88, 'massive_boost_15', 'system'),
('AUTOMATION: Le scoring email (ouvre, clique, repond) doit etre pondéré: ouvre=1pt, clique=3pts, repond=10pts.', 'Scoring email: ouvre=1, clique=3, repond=10', 'email', 'best_practice', 0.82, 'massive_boost_15', 'system'),
('COMMUNITY: Les communautes de marque (Discord, Facebook Group) ont un taux de retention 37% superieur aux non-membres.', 'Communaute marque = +37% retention', 'marketing', 'insight', 0.82, 'massive_boost_15', 'system'),
('COMMUNITY: Le contenu genere par la communaute (UGC) a 4x plus de confiance que le contenu de marque.', 'UGC communaute = 4x confiance vs marque', 'marketing', 'insight', 0.85, 'massive_boost_15', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('STRATEGIE: La matrice BCG (star, vache a lait, dilemme, poids mort) aide a prioriser les investissements produit.', 'Matrice BCG pour priorisation produit', 'ceo', 'best_practice', 0.85, 'massive_boost_16', 'system'),
('STRATEGIE: Le product-market fit se mesure par le Sean Ellis test: 40%+ des users seraient tres decus sans le produit.', 'PMF = 40%+ tres decus (Sean Ellis)', 'ceo', 'insight', 0.90, 'massive_boost_16', 'system'),
('STRATEGIE: La regle du 10x: un produit doit etre 10x meilleur que l alternative pour changer les habitudes des clients.', '10x meilleur = changer habitudes', 'ceo', 'insight', 0.85, 'massive_boost_16', 'system'),
('STRATEGIE: Les entreprises qui pivotent 1-2 fois ont 3x plus de chances de reussir que celles qui ne pivotent jamais.', 'Pivot 1-2x = 3x chances de succes', 'ceo', 'insight', 0.82, 'massive_boost_16', 'system'),
('STRATEGIE: Le moat (avantage competitif durable) le plus fort en SaaS: data network effect + switching costs eleves.', 'SaaS moat: data network effect + switching costs', 'ceo', 'insight', 0.88, 'massive_boost_16', 'system'),
('VENTE: La methode BANT (Budget, Autorite, Need, Timeline) qualifie un prospect en 4 questions.', 'BANT = qualifier prospect en 4 questions', 'commercial', 'best_practice', 0.85, 'massive_boost_16', 'system'),
('VENTE: Les demos personnalisees (avec les donnees du prospect) convertissent 3x mieux que les demos generiques.', 'Demo personnalisee = 3x conversion vs generique', 'commercial', 'insight', 0.88, 'massive_boost_16', 'system'),
('VENTE: Le follow-up optimal: J+1, J+3, J+7, J+14, J+30. 80% des ventes se font entre le 5e et le 12e contact.', 'Follow-up: J1,J3,J7,J14,J30. 80% ventes au 5-12e contact', 'commercial', 'best_practice', 0.90, 'massive_boost_16', 'system'),
