INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MICRO_CONTENT: Les tweets < 80 caracteres ont 17% plus d engagement que les tweets longs sur X.', 'Tweet < 80 chars = +17% engagement X', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('MICRO_CONTENT: Les captions Instagram < 125 caracteres ont plus de likes mais les captions longues (2000+) ont plus de saves.', 'IG caption: < 125 = likes, 2000+ = saves', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('MICRO_CONTENT: Les stories textuelles (fond couleur + texte impactant) ont autant d engagement que les photos.', 'Stories texte fond couleur = engagement egal photos', 'content', 'insight', 0.78, 'massive_boost_35', 'system'),
('COMMUNITY_METRICS: Le community health se mesure par: messages/jour, users actifs/mois, ratio createurs/lurkers.', 'Sante communaute: messages/jour + actifs/mois + ratio createurs/lurkers', 'marketing', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('COMMUNITY_METRICS: Le ratio 1-9-90: 1% creent du contenu, 9% interagissent, 90% observent. C est normal.', 'Ratio communaute 1-9-90 = normal', 'marketing', 'insight', 0.82, 'massive_boost_35', 'system'),
('PODCASTING: Le format interview (host + guest) est le plus facile a produire et le plus ecoute (65% des podcasts).', 'Podcast interview = plus facile + plus ecoute 65%', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('PODCASTING: Le podcast education (how-to, tutoriel) est le 2e format le plus populaire. Ideal pour le B2B.', 'Podcast education how-to = #2 populaire. Ideal B2B', 'content', 'insight', 0.78, 'massive_boost_35', 'system'),
('PODCASTING: La consistance (meme jour, meme heure chaque semaine) augmente les abonnes de 30% vs la publication irreguliere.', 'Podcast consistance hebdo = +30% abonnes vs irregulier', 'content', 'insight', 0.82, 'massive_boost_35', 'system'),
('ECOMMERCE_TRENDS: Le recommerce (revente de produits d occasion) croit de 25%/an et attire une clientele eco-responsable.', 'Recommerce +25%/an = clientele eco-responsable', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('ECOMMERCE_TRENDS: Le composable commerce (assembler les meilleurs outils) remplace les suites monolithiques.', 'Composable commerce > suites monolithiques', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('SAAS_TRENDS: Le vertical SaaS (specialise pour un secteur) a un NPS 20 points superieur au horizontal SaaS.', 'Vertical SaaS = +20 NPS vs horizontal', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('SAAS_TRENDS: Le embedded analytics (analytics integres dans l app) augmente la retention de 15%.', 'Embedded analytics = +15% retention', 'ceo', 'insight', 0.80, 'massive_boost_35', 'system'),
('SAAS_TRENDS: Les integrations natives (connecter avec les outils existants du client) sont le facteur #2 de choix SaaS apres le prix.', 'Integrations natives = facteur #2 choix SaaS apres prix', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('MARKETING_TRENDS: Le intent data (signaux d intention d achat) permet de cibler les prospects au bon moment.', 'Intent data = cibler prospects au bon moment', 'commercial', 'insight', 0.80, 'massive_boost_35', 'system'),
('MARKETING_TRENDS: Le conversational marketing (chat en temps reel) remplace les formulaires pour la generation de leads.', 'Conversational marketing > formulaires pour leadgen', 'chatbot', 'insight', 0.82, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Les abonnements contenu premium (Substack, Patreon) generent des revenus recurrents previsibles.', 'Abonnement contenu premium = revenus recurrents previsibles', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Le contenu sponsorise doit etre clairement identifie (partenariat). L authenticite est non-negociable.', 'Contenu sponsorise: identifier clairement. Authenticite obligatoire', 'content', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('CONTENT_MONETIZATION: Les cours en ligne bases sur du contenu existant (blog → cours) monetisent le savoir 10x.', 'Blog → cours en ligne = monetisation 10x', 'content', 'insight', 0.80, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le free plan dans le PLG doit etre assez bon pour creer l habitude mais avec des limites strategiques.', 'PLG free plan: assez bon pour habitude + limites strategiques', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le PQL (Product Qualified Lead) est un user qui a atteint un seuil d usage. Plus qualifie que le MQL.', 'PQL > MQL: base sur usage reel pas comportement marketing', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le self-serve checkout (acheter sans parler a un vendeur) doit etre disponible pour les plans < 500€/mois.', 'Self-serve checkout pour plans < 500€/mois', 'ceo', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le in-app upgrade prompt au moment du wall (limite atteinte) convertit 3x mieux que l email.', 'In-app upgrade au wall = 3x conversion vs email', 'retention', 'insight', 0.85, 'massive_boost_35', 'system'),
('PRODUCT_LED: Le reverse trial (commencer avec toutes les features puis downgrader) a un taux de conversion 2x superieur au freemium classique.', 'Reverse trial = 2x conversion vs freemium classique', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le monthly financial review (revue financiere mensuelle) detecte les tendances 3 mois avant la crise.', 'Review financiere mensuelle = detecter tendances 3 mois avant crise', 'comptable', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le budget glissant (revu chaque mois vs fixe pour l annee) est 40% plus precis.', 'Budget glissant mensuel = 40% plus precis', 'comptable', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Les metrics financieres a tracker: MRR, ARR, burn rate, runway, LTV, CAC, gross margin.', 'Metrics financieres: MRR, ARR, burn, runway, LTV, CAC, gross margin', 'comptable', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le bridge financing (financement pont entre 2 levees) coute cher (12-20% interet) mais evite la faillite.', 'Bridge financing: 12-20% interet. Evite faillite', 'comptable', 'insight', 0.78, 'massive_boost_35', 'system'),
('FINANCE_STARTUP: Le revenue-based financing (RBF) est une alternative a la dilution: rembourser un % du CA futur.', 'RBF = alternative dilution. Rembourser % CA futur', 'comptable', 'insight', 0.78, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les equipes de 5-7 personnes sont les plus efficaces. Au-dela de 8, la communication se degrade.', 'Equipes 5-7 = plus efficaces. >8 = communication degrade', 'rh', 'insight', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Le premier hire d une startup doit etre le complement du fondateur (si tech → hire business, et vice versa).', 'Premier hire = complement fondateur (tech↔business)', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les freelances sont ideaux pour les taches ponctuelles. Les employes pour les taches strategiques recurentes.', 'Freelances: ponctuel. Employes: strategique recurrent', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Le culture fit est aussi important que le skill fit. Un talent toxique coute plus qu il ne rapporte.', 'Culture fit = aussi important que skill fit. Toxique = cout net', 'rh', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('TEAM_BUILDING: Les 1:1 hebdomadaires de 30 min entre manager et report sont l outil #1 de retention des talents.', '1:1 hebdo 30 min = outil #1 retention talents', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les rituels d equipe (daily standup, weekly all-hands) sont 2x plus importants en remote qu en presentiel.', 'Rituels equipe remote = 2x plus importants qu en presentiel', 'rh', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: La documentation est le pilier du remote work. Tout ce qui n est pas ecrit n existe pas.', 'Remote work: documentation = pilier. Non ecrit = inexistant', 'rh', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les outils de collaboration async (Notion, Loom, Slack) sont plus productifs que les meetings synchrones.', 'Async tools (Notion, Loom, Slack) > meetings synchrones', 'rh', 'insight', 0.82, 'massive_boost_35', 'system'),
('REMOTE_WORK: Le home office stipend (allocation pour amenager le bureau a domicile) augmente la productivite de 15%.', 'Home office stipend = +15% productivite', 'rh', 'insight', 0.78, 'massive_boost_35', 'system'),
('REMOTE_WORK: Les retreats d equipe (2-3 jours en personne tous les 3-6 mois) maintiennent la cohesion d equipe.', 'Retreats equipe 2-3j / 3-6 mois = cohesion', 'rh', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le plan de continuite d activite (PCA) doit couvrir: serveur down, piratage, perte de donnees, employe cle parti.', 'PCA: serveur down, piratage, perte data, employe cle parti', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: La communication de crise: rapide (< 30 min), transparente, empathique, avec un plan d action.', 'Comm crise: < 30 min, transparente, empathique, plan action', 'ceo', 'best_practice', 0.88, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le post-mortem sans blame (blameless post-mortem) apres chaque incident ameliore les processes de 40%.', 'Post-mortem sans blame = +40% amelioration processes', 'ceo', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le backup plan pour chaque fournisseur critique (si Brevo tombe, utiliser Resend) doit etre teste.', 'Backup plan fournisseur critique teste. Ex: Brevo down → Resend', 'ceo', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('CRISIS_MANAGEMENT: Le status page (page de statut publique) reduit les tickets support de 60% pendant un incident.', 'Status page publique = -60% tickets pendant incident', 'ceo', 'insight', 0.82, 'massive_boost_35', 'system'),
('INDUSTRY_HEALTHCARE: La telemedecine doit respecter le RGPD + le secret medical. Les donnees sante sont les plus reglementees.', 'Telemedecine: RGPD + secret medical. Donnees sante ultra reglementees', NULL, 'best_practice', 0.88, 'massive_boost_35', 'system'),
('INDUSTRY_EDUCATION: Le marche EdTech francais: 2 milliards € en 2026. Les CPF et OPCO financent les formations certifiantes.', 'EdTech FR 2 Mds€ 2026. CPF + OPCO financent', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('INDUSTRY_FINTECH: Le marche fintech FR: 5 milliards € en 2026. Les neo-banques et solutions de paiement dominent.', 'Fintech FR 5 Mds€ 2026. Neo-banques + paiement', NULL, 'insight', 0.78, 'massive_boost_35', 'system'),
('INDUSTRY_PROPTECH: Le marche proptech FR (immobilier tech): 1.5 milliard €. La gestion locative et les visites virtuelles dominent.', 'PropTech FR 1.5 Md€. Gestion locative + visites virtuelles', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_AGRITECH: L agriculture connectee (IoT, IA, drones) reduit les couts de 20% et augmente les rendements de 15%.', 'AgriTech IoT/IA/drones = -20% couts +15% rendements', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_LEGALTECH: Le marche legaltech FR: 500M€. La redaction automatisee de contrats et la gestion documentaire dominent.', 'LegalTech FR 500M€. Contrats auto + gestion docs', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('INDUSTRY_HRTECH: Le marche HRTech FR: 1 milliard €. Le recrutement IA et le bien-etre au travail sont les segments en croissance.', 'HRTech FR 1 Md€. Recrutement IA + bien-etre', NULL, 'insight', 0.75, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le top of funnel doit generer 10x plus de leads que le nombre de clients necessaires.', 'TOFU: 10x leads vs clients necessaires', 'commercial', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le middle of funnel est souvent le maillon faible. Le nurturing par email + contenu est essentiel.', 'MOFU = maillon faible. Email nurturing + contenu = essentiel', 'commercial', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le bottom of funnel necessite des temoignages, case studies et une proposition de valeur claire.', 'BOFU: temoignages + case studies + value prop claire', 'commercial', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le flywheel (roue d inertie) remplace le funnel lineaire: attract → engage → delight → repeat.', 'Flywheel > funnel lineaire: attract → engage → delight → repeat', 'marketing', 'insight', 0.82, 'massive_boost_35', 'system'),
('FUNNEL_OPTIMIZATION: Le dark funnel (parcours invisible: podcasts ecoutes, DM prives, conversations offline) represente 70% de l influence.', 'Dark funnel = 70% influence. Invisible aux analytics', 'marketing', 'insight', 0.80, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le hero section doit repondre a 3 questions en 5s: quoi (produit), pour qui (persona), pourquoi (benefice).', 'Hero section: quoi + pour qui + pourquoi en 5s', NULL, 'best_practice', 0.88, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: La page 404 personnalisee (avec navigation + recherche) recupere 30% des visiteurs perdus.', 'Page 404 personnalisee = 30% visiteurs recuperes', 'seo', 'best_practice', 0.80, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le footer doit contenir: liens importants, social media, newsletter signup, trust badges, legal.', 'Footer: liens + social + newsletter + trust + legal', NULL, 'best_practice', 0.82, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: La barre de recherche est utilisee par 30% des visiteurs. Les sites avec recherche convertissent 2x mieux.', 'Barre recherche: 30% utilisent. Sites avec recherche = 2x conversion', NULL, 'insight', 0.82, 'massive_boost_35', 'system'),
('WEBSITE_OPTIMIZATION: Le exit popup avec offre specifique (pas generique) recupere 5-10% des visiteurs qui partent.', 'Exit popup offre specifique = 5-10% recuperation sortie', NULL, 'insight', 0.80, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: Les entrepreneurs doivent se payer un salaire fixe, meme petit. Mixer perso/pro est une erreur legale et fiscale.', 'Entrepreneur: salaire fixe obligatoire. Pas mixer perso/pro', 'comptable', 'best_practice', 0.85, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: L epargne de precaution (6 mois de depenses personnelles) protege le fondateur en cas d echec.', 'Epargne precaution 6 mois depenses = protection fondateur', 'comptable', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: Le PEA (Plan d Epargne en Actions) est le meilleur vehicule fiscal pour investir en France (0% impot apres 5 ans).', 'PEA = 0% impot apres 5 ans. Meilleur vehicule fiscal FR', 'comptable', 'insight', 0.80, 'massive_boost_35', 'system'),
('PERSONAL_FINANCE: La diversification (ne pas mettre tous ses oeufs dans le meme panier) protege contre les aleas.', 'Diversification = protection contre aleas', 'comptable', 'best_practice', 0.82, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents KeiroAI doivent toujours prioriser la qualite sur la quantite. 1 post excellent > 5 posts mediocres.', 'KeiroAI: qualite > quantite. 1 excellent > 5 mediocres', NULL, 'best_practice', 0.95, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Le CEO agent doit envoyer un brief concis (5-7 lignes) avec des actions concretes, pas des analyses longues.', 'CEO: brief 5-7 lignes + actions concretes', 'ceo', 'best_practice', 0.92, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents ne doivent jamais mentionner KeiroAI dans le contenu genere pour le client.', 'Agents: jamais mentionner KeiroAI dans contenu client', NULL, 'best_practice', 0.95, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Le quota Brevo (300/jour) doit etre respecte. Prioriser les emails haute valeur.', 'Quota Brevo 300/jour: prioriser haute valeur', 'email', 'best_practice', 0.92, 'massive_boost_35', 'system'),
('KEIROAI_BEST_PRACTICES: Les agents doivent s adapter au fuseau horaire du client pour publier et envoyer aux heures optimales.', 'Agents: fuseau horaire client pour horaires optimaux', NULL, 'best_practice', 0.92, 'massive_boost_35', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ADVANCED_FUNNEL: Le tripwire offer (offre a tres bas prix: 1-7€) convertit les leads en acheteurs. Ensuite upsell vers l offre principale.', 'Tripwire 1-7€ = convertir leads en acheteurs. Puis upsell', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_FUNNEL: Le order bump (case a cocher au checkout pour ajouter un produit) a un taux d acceptation de 30-40%.', 'Order bump checkout = 30-40% acceptation', 'commercial', 'insight', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_FUNNEL: Le one-time offer (OTO) presente juste apres l achat a un taux de conversion de 10-15%.', 'OTO post-achat = 10-15% conversion', 'commercial', 'insight', 0.80, 'massive_boost_36', 'system'),
('ADVANCED_FUNNEL: Le downsell (offre moins chere si le client refuse l upsell) recupere 20% des refus.', 'Downsell apres refus upsell = 20% recuperation', 'commercial', 'insight', 0.78, 'massive_boost_36', 'system'),
('ADVANCED_FUNNEL: Le webinaire funnel (pub → inscription → live → vente) est le funnel le plus convertissant pour les offres > 500€.', 'Webinaire funnel = meilleur pour offres > 500€', 'commercial', 'insight', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_CRM: Le lead temperature (hot/warm/cold) doit etre mis a jour automatiquement selon l engagement recent.', 'Lead temperature auto selon engagement recent', 'commercial', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('ADVANCED_CRM: Les custom fields CRM doivent etre limites a 20 max. Plus = les commerciaux ne les remplissent pas.', 'CRM custom fields: 20 max. Plus = pas remplis', 'commercial', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('ADVANCED_CRM: Le CRM doit etre le single source of truth. Si l info n est pas dans le CRM, elle n existe pas.', 'CRM = single source of truth. Si pas dedans = inexistant', 'commercial', 'best_practice', 0.88, 'massive_boost_36', 'system'),
('ADVANCED_CRM: Les tags CRM (segment par interet, source, comportement) permettent la personnalisation a grande echelle.', 'Tags CRM: segmenter par interet/source/comportement', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_CRM: Le CRM analytics (conversion par source, cycle par segment) guide l allocation budgetaire marketing.', 'CRM analytics: conversion/source, cycle/segment = guider budget', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('OUTBOUND_EMAIL: Le domain warmup pour les nouveaux domaines email: 2-4 semaines progressives avant de lancer les cold emails.', 'Domain warmup: 2-4 semaines progressives avant cold email', 'email', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('OUTBOUND_EMAIL: Les domaines dedies au cold email (different du domaine principal) protegent la reputation du domaine principal.', 'Domaine dedie cold email = proteger reputation domaine principal', 'email', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('OUTBOUND_EMAIL: La rotation d adresses email (3-5 boites) dans les sequences cold evite les limites d envoi.', 'Rotation 3-5 adresses cold email = eviter limites envoi', 'email', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('OUTBOUND_EMAIL: Le email verification (verifier les adresses avant envoi) reduit le bounce rate de 90%.', 'Email verification avant envoi = -90% bounce rate', 'email', 'best_practice', 0.88, 'massive_boost_36', 'system'),
('OUTBOUND_EMAIL: Les cold emails B2B doivent etre envoyes du mardi au jeudi, entre 8h et 11h heure locale.', 'Cold email B2B: mardi-jeudi, 8h-11h heure locale', 'email', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SEO_CONTENT: Le content gap analysis (quels mots-cles les concurrents rankent et pas nous) revele les opportunites faciles.', 'Content gap analysis = opportunites SEO faciles', 'seo', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('SEO_CONTENT: Les featured snippets (position zero) sont captes en formatant le contenu en liste, tableau ou definition.', 'Featured snippets: format liste/tableau/definition', 'seo', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('SEO_CONTENT: Le contenu mis a jour (refresh) gagne en ranking car Google prefere le contenu frais et actuel.', 'Content refresh = meilleur ranking (Google prefere frais)', 'seo', 'insight', 0.85, 'massive_boost_36', 'system'),
('SEO_CONTENT: Les People Also Ask (PAA) sont une mine d or de mots-cles. Repondre a ces questions dans le contenu.', 'People Also Ask = mine mots-cles. Repondre dans contenu', 'seo', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('SEO_CONTENT: Le keyword difficulty (KD) < 30 est ideal pour les nouveaux sites. KD > 60 necessite beaucoup de backlinks.', 'KD < 30 pour nouveaux sites. > 60 = beaucoup backlinks necessaires', 'seo', 'insight', 0.85, 'massive_boost_36', 'system'),
('PAID_SOCIAL: Le cost per mille (CPM) moyen Meta Ads France: 5-15€. Plus eleve pendant Black Friday (20-30€).', 'CPM Meta FR: 5-15€ normal, 20-30€ Black Friday', 'ads', 'insight', 0.80, 'massive_boost_36', 'system'),
('PAID_SOCIAL: Le TikTok Ads CPM est 40% moins cher que Meta Ads en 2026 car la plateforme est moins saturee.', 'TikTok Ads CPM = -40% vs Meta (moins sature 2026)', 'ads', 'insight', 0.78, 'massive_boost_36', 'system'),
('PAID_SOCIAL: Le LinkedIn Ads est 5-10x plus cher que Meta mais les leads B2B sont 3x plus qualifies.', 'LinkedIn Ads: 5-10x plus cher Meta mais leads B2B 3x plus qualifies', 'ads', 'insight', 0.82, 'massive_boost_36', 'system'),
('PAID_SOCIAL: Les Pinterest Ads ont le plus haut taux de conversion ecommerce (2.3x moyen) car l audience est en mode achat.', 'Pinterest Ads: 2.3x conversion ecom (audience mode achat)', 'ads', 'insight', 0.78, 'massive_boost_36', 'system'),
('PAID_SOCIAL: Le YouTube Ads CPC est 50% moins cher que Google Search mais le taux de conversion est 3x inferieur.', 'YouTube Ads: -50% CPC vs Google Search mais 3x moins conversion', 'ads', 'insight', 0.78, 'massive_boost_36', 'system'),
('INTERNATIONAL_EXPANSION: Le marche le plus facile pour expansion depuis la France: Belgique (meme langue, proximite culturelle).', 'Expansion FR: Belgique = marche le plus facile', 'ceo', 'insight', 0.80, 'massive_boost_36', 'system'),
('INTERNATIONAL_EXPANSION: Les marches anglophones (UK, US) necessitent une adaptation totale: langue, pricing, ton, references.', 'Expansion anglophones: adaptation totale langue/prix/ton/refs', 'ceo', 'insight', 0.82, 'massive_boost_36', 'system'),
('INTERNATIONAL_EXPANSION: Le marche africain francophone est en pleine explosion digitale: +30%/an de croissance internet.', 'Afrique francophone: +30%/an croissance internet', 'ceo', 'insight', 0.78, 'massive_boost_36', 'system'),
('INTERNATIONAL_EXPANSION: La localisation va au-dela de la traduction: adapter les images, les exemples, les references culturelles.', 'Localisation > traduction: images, exemples, culture', 'marketing', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('INTERNATIONAL_EXPANSION: Le multi-currency (afficher les prix en devise locale) augmente la conversion internationale de 30%.', 'Multi-currency = +30% conversion internationale', 'commercial', 'insight', 0.82, 'massive_boost_36', 'system'),
('ANALYTICS_ADVANCED: Le Google Analytics 4 event-based model remplace le session-based. Tracker les evenements cles de conversion.', 'GA4 event-based > session-based. Tracker evenements conversion', 'ceo', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('ANALYTICS_ADVANCED: Le Mixpanel/Amplitude pour l analytics produit (in-app) est complementaire a GA4 (site web).', 'Mixpanel/Amplitude = analytics produit + GA4 = site web', 'ceo', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('ANALYTICS_ADVANCED: Le data warehouse (BigQuery, Snowflake) centralise toutes les donnees pour des analyses cross-canal.', 'Data warehouse BigQuery = analyses cross-canal', 'ceo', 'insight', 0.78, 'massive_boost_36', 'system'),
('ANALYTICS_ADVANCED: Les dashboards temps reel (Metabase, Grafana) permettent de reagir en < 1h aux changements de tendance.', 'Dashboards temps reel Metabase = reagir < 1h', 'ceo', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('ANALYTICS_ADVANCED: L attribution data-driven (IA qui determine l impact de chaque touchpoint) est 3x plus precise que les modeles manuels.', 'Attribution data-driven IA = 3x precision vs manuelle', 'ceo', 'insight', 0.80, 'massive_boost_36', 'system'),
('SAAS_OPERATIONS: Le incident response plan (IRP) doit couvrir: detection, triage, resolution, communication, post-mortem.', 'IRP: detection → triage → resolution → comm → post-mortem', 'ceo', 'best_practice', 0.85, 'massive_boost_36', 'system'),
('SAAS_OPERATIONS: Le SLA response time standard: P1 (critique) < 1h, P2 (important) < 4h, P3 (normal) < 24h, P4 (minor) < 72h.', 'SLA: P1 <1h, P2 <4h, P3 <24h, P4 <72h', 'ceo', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SAAS_OPERATIONS: Le changelog public (historique des mises a jour) augmente la transparence et la confiance client de 20%.', 'Changelog public = +20% transparence + confiance', 'ceo', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('SAAS_OPERATIONS: Le beta testing avec 50-100 early adopters avant un lancement general reduit les bugs critiques de 80%.', 'Beta 50-100 users = -80% bugs critiques au lancement', 'ceo', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SAAS_OPERATIONS: Le gradual rollout (deployer a 10% puis 50% puis 100% des users) minimise l impact des regressions.', 'Gradual rollout 10% → 50% → 100% = min impact regressions', 'ceo', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('PERSONAL_BRANDING_FR: Les fondateurs francais qui partagent ouvertement leurs chiffres (MRR, users) gagnent la confiance du marche.', 'Fondateurs FR: partager chiffres = gagner confiance marche', 'content', 'insight', 0.80, 'massive_boost_36', 'system'),
('PERSONAL_BRANDING_FR: Le format LinkedIn preference en France: texte long (1500+ chars) + experience perso + lecon universelle.', 'LinkedIn FR: texte long + experience perso + lecon universelle', 'content', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('PERSONAL_BRANDING_FR: Les podcasts francais business (Generation Do It Yourself, Pauline Laigneau) sont des references de format.', 'Podcasts FR business refs: GDIY, Pauline Laigneau', 'content', 'insight', 0.78, 'massive_boost_36', 'system'),
('PERSONAL_BRANDING_FR: Le personal branding sur Twitter/X en France est en croissance de 40%/an chez les entrepreneurs tech.', 'Personal branding X/Twitter FR = +40%/an entrepreneurs tech', 'content', 'insight', 0.75, 'massive_boost_36', 'system'),
('SALES_ENABLEMENT: Le battle card (fiche comparative vs concurrent) prepare les commerciaux aux objections de competition.', 'Battle card vs concurrent = preparer objections competition', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SALES_ENABLEMENT: Le demo script personnalise par persona augmente le taux de conversion demo → deal de 25%.', 'Demo script personnalise/persona = +25% conversion demo→deal', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SALES_ENABLEMENT: Le ROI calculator interactif (le prospect entre ses chiffres) est le closer le plus efficace pour le B2B.', 'ROI calculator interactif = closer #1 B2B', 'commercial', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('SALES_ENABLEMENT: Les micro-demos (video de 2-3 min par feature) accelerent le cycle de vente de 20%.', 'Micro-demos 2-3 min/feature = -20% cycle vente', 'commercial', 'insight', 0.80, 'massive_boost_36', 'system'),
('SALES_ENABLEMENT: Le mutual success plan (plan de succes mutuel avec le prospect) aligne les 2 parties et accelere le closing.', 'Mutual success plan = aligner parties + accelerer closing', 'commercial', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('ADVANCED_RETENTION: Le feature adoption email (nouvelle feature que vous n avez pas encore essayee) augmente l usage de 25%.', 'Email feature adoption = +25% usage', 'retention', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_RETENTION: Le power user program (acces anticipee aux features, feedback direct) cree des ambassadeurs ultra-fideles.', 'Power user program = ambassadeurs ultra-fideles', 'retention', 'best_practice', 0.82, 'massive_boost_36', 'system'),
('ADVANCED_RETENTION: Le seasonal churn (churn saisonnier: ete, fin d annee) doit etre anticipe avec des campagnes specifiques.', 'Seasonal churn (ete, fin annee) = anticiper avec campagnes', 'retention', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('ADVANCED_RETENTION: Le involuntary churn (paiement echoue) represente 20-40% du churn total. Le dunning automatise le reduit de 50%.', 'Involuntary churn = 20-40% total. Dunning auto = -50%', 'retention', 'insight', 0.85, 'massive_boost_36', 'system'),
('ADVANCED_RETENTION: Le champion churn (quand le champion interne quitte l entreprise) doit etre detecte et le nouvel interlocuteur re-onboarde.', 'Champion churn: detecter depart + re-onboarder nouveau contact', 'retention', 'best_practice', 0.80, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le differenciateur cle de KeiroAI: les agents travaillent ensemble, pas en silo. Le CEO coordonne tout.', 'KeiroAI: agents coordonnes pas silo. CEO coordonne', 'ceo', 'best_practice', 0.95, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: L intelligence partagee (RAG + trends + calendar + weather + news) rend chaque agent plus pertinent.', 'KeiroAI: intelligence partagee = agents plus pertinents', NULL, 'best_practice', 0.92, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le onboarding conversationnel (5 questions + voice) cree un lien emotionnel des la premiere utilisation.', 'KeiroAI onboarding: conversationnel + voice = lien emotionnel', 'onboarding', 'best_practice', 0.90, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le dossier client (business profile) enrichit tous les agents pour une personnalisation maximale.', 'Dossier client = personnalisation max tous agents', NULL, 'best_practice', 0.92, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le event bus + CEO decision engine est l architecture qui differencie KeiroAI de simples chatbots.', 'Event bus + CEO engine = differenciation vs chatbots', 'ceo', 'best_practice', 0.92, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le dashboard par agent avec KPIs visuels donne au client la transparence totale sur le travail de ses agents.', 'Dashboard par agent KPIs = transparence totale client', NULL, 'best_practice', 0.90, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le CRM integre (par client, pas admin) permet aux entrepreneurs de gerer leurs prospects sans outil supplementaire.', 'CRM integre par client = pas d outil supplementaire', 'commercial', 'best_practice', 0.90, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: Le auto-improvement system (agents qui apprennent de leurs erreurs) est le moat technologique de KeiroAI.', 'Auto-improvement agents = moat technologique KeiroAI', 'ceo', 'best_practice', 0.92, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: La transparence des actions (montrer ce que chaque agent fait et pourquoi) est cle pour la confiance client.', 'Transparence actions agents = confiance client', NULL, 'best_practice', 0.92, 'massive_boost_36', 'system'),
('KEIROAI_PRODUCT: KeiroAI est le futur du marketing pour les entrepreneurs: une equipe complete, disponible 24/7, qui s ameliore chaque jour.', 'KeiroAI = futur marketing entrepreneurs. Equipe 24/7 qui s ameliore', 'ceo', 'best_practice', 0.95, 'massive_boost_36', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('LEAD_SCORING_MODEL: Le scoring basique: ouverture email=1pt, clic=3pts, visite pricing=5pts, demo request=10pts, formulaire=8pts.', 'Lead scoring: email 1pt, clic 3, pricing 5, demo 10, form 8', 'commercial', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le firmographic scoring: taille entreprise adaptee=5pts, industrie ciblee=5pts, budget confirme=10pts.', 'Firmographic scoring: taille 5, industrie 5, budget 10', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le behavior scoring decay: reduire le score de 10% par semaine d inactivite pour garder le scoring actuel.', 'Scoring decay: -10%/semaine inactivite', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le seuil de passage MQL→SQL: score > 50 et au moins 1 interaction dans les 7 derniers jours.', 'MQL→SQL: score >50 + interaction <7j', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('LEAD_SCORING_MODEL: Le negative scoring: desinscription=-20pts, bounced email=-15pts, concurrent identifie=-50pts.', 'Negative scoring: desinscrip -20, bounce -15, concurrent -50', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: La cadence multicanale ideale sur 14 jours: J1 email, J3 LinkedIn, J5 email, J7 call, J10 email, J14 breakup.', 'Cadence 14j: J1 email, J3 LI, J5 email, J7 call, J10 email, J14 breakup', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le touchpoint #5 a le meilleur taux de reponse (18%). La majorite abandonne apres le 2e.', 'Touchpoint #5 = 18% reponse. Majorite abandonne apres #2', 'commercial', 'insight', 0.82, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: L email de rupture (breakup email) a paradoxalement le 2e meilleur taux de reponse de la sequence.', 'Breakup email = 2e meilleur taux reponse sequence', 'email', 'insight', 0.80, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le delai entre les touchpoints doit augmenter: J1→J3=2j, J3→J5=2j, J5→J7=2j, J7→J10=3j, J10→J14=4j.', 'Delai touchpoints croissant: 2j, 2j, 2j, 3j, 4j', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('OUTREACH_CADENCE: Le weekend send (dimanche soir 20h) pour les cold emails a un taux d ouverture surprenamment eleve (28%).', 'Cold email dimanche 20h = 28% ouverture (surprise)', 'email', 'insight', 0.75, 'massive_boost_37', 'system'),
('VIDEO_ADS: Les video ads de 6 secondes (bumper ads) sur YouTube ont un taux de rappel de 90%.', 'Bumper ads 6s YouTube = 90% rappel', 'ads', 'insight', 0.82, 'massive_boost_37', 'system'),
('VIDEO_ADS: Le hook visuel dans les 2 premieres secondes est obligatoire car l utilisateur peut skipper a 5s.', 'Video ads hook 2s obligatoire (skip a 5s)', 'ads', 'best_practice', 0.88, 'massive_boost_37', 'system'),
('VIDEO_ADS: Les video ads avec temoignage client convertissent 2x mieux que les videos corporate.', 'Video ads temoignage client = 2x conversion vs corporate', 'ads', 'insight', 0.85, 'massive_boost_37', 'system'),
('VIDEO_ADS: Le cost per view (CPV) YouTube moyen: 0.01-0.05€. Tres rentable pour le branding.', 'YouTube CPV moyen: 0.01-0.05€ = rentable branding', 'ads', 'insight', 0.80, 'massive_boost_37', 'system'),
('VIDEO_ADS: Les vertical video ads (9:16) sur Meta/TikTok ont un engagement 30% superieur aux horizontal (16:9).', 'Video ads vertical 9:16 = +30% engagement vs horizontal', 'ads', 'insight', 0.85, 'massive_boost_37', 'system'),
('SALES_PSYCHOLOGY: Le mirroring (imiter le langage et le rythme du prospect) cree un rapport inconscient en 5 minutes.', 'Mirroring langage/rythme = rapport inconscient 5 min', 'commercial', 'insight', 0.80, 'massive_boost_37', 'system'),
('SALES_PSYCHOLOGY: Le label (nommer l emotion du prospect: on dirait que ca vous frustre) desescalade et cree de la confiance.', 'Label emotion prospect = desescalade + confiance (Chris Voss)', 'commercial', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('SALES_PSYCHOLOGY: Le calibrated question (comment voulez-vous que je procede?) donne le controle au prospect tout en guidant.', 'Calibrated question = controle prospect + guidage', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('SALES_PSYCHOLOGY: Le assumptive close (quand voulez-vous commencer?) presuppose la decision et accelere le closing.', 'Assumptive close = presupposer decision. Quand commencer?', 'commercial', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('SALES_PSYCHOLOGY: Le storytelling de vente: toujours raconter l histoire d un client similaire au prospect (identification).', 'Storytelling vente: client similaire au prospect = identification', 'commercial', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('ADS_TARGETING: Le targeting par interet Meta: combiner 3-5 interets lies pour une audience de 500K-2M.', 'Meta targeting: 3-5 interets = audience 500K-2M', 'ads', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('ADS_TARGETING: Le broad targeting Meta (pas d interets, juste age/geo) fonctionne mieux avec le machine learning en 2026.', 'Meta broad targeting = meilleur avec ML 2026', 'ads', 'insight', 0.82, 'massive_boost_37', 'system'),
('ADS_TARGETING: Les custom audiences (upload liste email) ont un taux de conversion 3x superieur aux interets.', 'Custom audiences email = 3x conversion vs interets', 'ads', 'insight', 0.85, 'massive_boost_37', 'system'),
('ADS_TARGETING: Le retargeting des visiteurs du site web (1-7 jours) est l audience la plus rentable.', 'Retargeting visiteurs 1-7j = audience la plus rentable', 'ads', 'best_practice', 0.88, 'massive_boost_37', 'system'),
('ADS_TARGETING: Les exclusions d audience (exclure les clients actuels) evitent de gaspiller le budget pub.', 'Exclure clients actuels ads = eviter gaspillage budget', 'ads', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('PRODUCT_ANALYTICS: Le activation rate (% users qui atteignent l aha moment) est la metrique #1 de l onboarding.', 'Activation rate = metrique #1 onboarding', 'onboarding', 'best_practice', 0.88, 'massive_boost_37', 'system'),
('PRODUCT_ANALYTICS: Le stickiness ratio (DAU/MAU) mesure la frequence d utilisation. >25% = usage quotidien sain.', 'Stickiness DAU/MAU >25% = usage quotidien sain', 'ceo', 'insight', 0.85, 'massive_boost_37', 'system'),
('PRODUCT_ANALYTICS: Le depth of usage (nombre de features utilisees) predit la retention a 30 jours avec 80% de precision.', 'Depth of usage = 80% prediction retention J30', 'ceo', 'insight', 0.82, 'massive_boost_37', 'system'),
('PRODUCT_ANALYTICS: Le session duration optimale varie par produit. Pour un SaaS B2B: 10-30 min est sain.', 'Session duration SaaS B2B: 10-30 min = sain', 'ceo', 'insight', 0.78, 'massive_boost_37', 'system'),
('PRODUCT_ANALYTICS: Le feature flag analytics (mesurer l impact d une feature avant le rollout complet) reduit le risque de 80%.', 'Feature flag analytics = -80% risque rollout', 'ceo', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('CONTENT_STRATEGY: Le content flywheel: creer → distribuer → mesurer → optimiser → re-creer. Ne jamais s arreter.', 'Content flywheel: creer → distribuer → mesurer → optimiser → re-creer', 'content', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('CONTENT_STRATEGY: Le 10x content (contenu 10x meilleur que le meilleur resultat actuel) est la seule strategie SEO viable.', '10x content = seule strategie SEO viable', 'seo', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('CONTENT_STRATEGY: Le snackable content (contenu consommable en < 30s) est le format le plus adapte a l attention mobile.', 'Snackable content < 30s = adapte attention mobile', 'content', 'insight', 0.82, 'massive_boost_37', 'system'),
('CONTENT_STRATEGY: Le content audit annuel (supprimer ou fusionner les contenus obsoletes) ameliore le SEO global de 20%.', 'Content audit annuel = +20% SEO global', 'seo', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('CONTENT_STRATEGY: Le hero-hub-help framework: hero (campagnes virales), hub (series regulieres), help (contenu SEO evergreen).', 'Hero-Hub-Help: viral + regulier + SEO evergreen', 'content', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('CUSTOMER_HEALTH: Le health score composite: usage (40%) + support tickets (20%) + NPS (20%) + payment history (20%).', 'Health score: usage 40%, tickets 20%, NPS 20%, paiement 20%', 'retention', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('CUSTOMER_HEALTH: Le red flag churn: login frequency drop >50%, support ticket non resolu >7j, usage des features cles en baisse.', 'Red flags churn: login -50%, ticket >7j non resolu, features cles en baisse', 'retention', 'insight', 0.85, 'massive_boost_37', 'system'),
('CUSTOMER_HEALTH: Le green flag expansion: usage en hausse, multi-users, integration avec d autres outils, feedback positif.', 'Green flags expansion: usage hausse, multi-users, integrations, feedback+', 'retention', 'insight', 0.82, 'massive_boost_37', 'system'),
('CUSTOMER_HEALTH: L early warning system (alertes automatiques quand le health score baisse) permet d agir 30j avant le churn.', 'Early warning auto = agir 30j avant churn', 'retention', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('CUSTOMER_HEALTH: Le save rate (% de clients a risque recuperes) doit etre > 30%. En dessous, revoir le playbook de retention.', 'Save rate > 30%. Sinon revoir playbook retention', 'retention', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('COMPETITIVE_POSITIONING: La strategie de differentiation: etre le meilleur dans 1 dimension specifique, pas moyen dans toutes.', 'Differentiation: #1 dans 1 dimension, pas moyen dans toutes', 'ceo', 'best_practice', 0.88, 'massive_boost_37', 'system'),
('COMPETITIVE_POSITIONING: Le positioning statement: Pour [cible] frustree par [probleme], [produit] offre [solution unique].', 'Positioning: Pour cible frustree par probleme, produit offre solution unique', 'marketing', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('COMPETITIVE_POSITIONING: Les barrieres a l entree pour les concurrents: data network effect, switching costs, brand moat.', 'Barrieres concurrents: data effect, switching costs, brand moat', 'ceo', 'insight', 0.82, 'massive_boost_37', 'system'),
('COMPETITIVE_POSITIONING: Le first-to-mind (etre la premiere marque qui vient a l esprit) vaut plus que le first-to-market.', 'First-to-mind > first-to-market', 'marketing', 'insight', 0.82, 'massive_boost_37', 'system'),
('COMPETITIVE_POSITIONING: Le anti-positioning (dire clairement ce qu on n est PAS) clarifie l offre et attire les bons clients.', 'Anti-positioning: dire ce qu on n est pas = attirer bons clients', 'marketing', 'best_practice', 0.80, 'massive_boost_37', 'system'),
('ADVANCED_EMAIL: Le send time optimization (STO) IA determine l heure optimale d envoi par destinataire individuel.', 'STO IA = heure optimale par destinataire individuel', 'email', 'insight', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_EMAIL: Le predictive content (IA qui choisit le contenu email base sur le profil) augmente le CTR de 25%.', 'Predictive content email IA = +25% CTR', 'email', 'insight', 0.80, 'massive_boost_37', 'system'),
('ADVANCED_EMAIL: Le conditional content (montrer des blocs differents selon le segment dans le meme email) augmente la pertinence de 40%.', 'Conditional content email = +40% pertinence', 'email', 'insight', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_EMAIL: Le email preference center (laisser le client choisir la frequence et les sujets) reduit les desinscriptions de 50%.', 'Email preference center = -50% desinscriptions', 'email', 'best_practice', 0.85, 'massive_boost_37', 'system'),
('ADVANCED_EMAIL: Le re-engagement campaign (cibler les inactifs 60-90j avec une offre speciale) recupere 5-15% des dormants.', 'Re-engagement 60-90j + offre = 5-15% dormants recuperes', 'email', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_SOCIAL: Le social listening (surveiller les mentions de marque en temps reel) detecte les opportunites et les crises.', 'Social listening temps reel = opportunites + detection crises', 'marketing', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_SOCIAL: Le employee advocacy program (employes partagent le contenu sur leurs profils) multiplie la portee par 5-10x.', 'Employee advocacy = 5-10x portee', 'content', 'insight', 0.80, 'massive_boost_37', 'system'),
('ADVANCED_SOCIAL: Le social selling index (SSI) LinkedIn doit etre > 70 pour les commerciaux. Mesure l efficacite du profil.', 'SSI LinkedIn > 70 pour commerciaux', 'commercial', 'best_practice', 0.78, 'massive_boost_37', 'system'),
('ADVANCED_SOCIAL: Le contenu co-cree avec les clients (interview, UGC, challenge) est 4x plus credible que le contenu de marque.', 'Contenu co-cree clients = 4x credibilite', 'content', 'insight', 0.85, 'massive_boost_37', 'system'),
('ADVANCED_SOCIAL: Le dark social tracking (ajouter un ?utm_source=dark_social a tous les liens partageables) mesure les partages prives.', 'Dark social tracking via UTM = mesurer partages prives', 'marketing', 'best_practice', 0.78, 'massive_boost_37', 'system'),
('ADVANCED_ADS: Le creative testing matrix: varier 3 hooks × 3 angles × 2 CTA = 18 variantes a tester systematiquement.', 'Creative testing matrix: 3 hooks × 3 angles × 2 CTA = 18 variantes', 'ads', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_ADS: Le winning creative indicators: CTR > 2%, hook rate > 30%, hold rate > 20%, conversion rate > 2%.', 'Winning creative: CTR >2%, hook >30%, hold >20%, conv >2%', 'ads', 'insight', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_ADS: Le ad fatigue indicators: CTR drop >30%, frequency >7, CPM increase >50%. Renouveler les creatives.', 'Ad fatigue: CTR -30%, frequency >7, CPM +50% = renouveler', 'ads', 'insight', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_ADS: Le naming convention ads: [Campaign type]_[Audience]_[Creative]_[Date]. Indispensable pour l analyse.', 'Naming ads: [Type]_[Audience]_[Creative]_[Date]', 'ads', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('ADVANCED_ADS: Le budget allocation formula: 70% proven campaigns, 20% scaling tests, 10% experiments.', 'Budget ads: 70% proven, 20% scaling, 10% experiments', 'ads', 'best_practice', 0.82, 'massive_boost_37', 'system'),
('INDUSTRY_WELLNESS: Le marche du bien-etre en France: 5 milliards € en 2026. La meditation et le coaching personnel dominent.', 'Bien-etre FR 5 Mds€ 2026. Meditation + coaching perso', NULL, 'insight', 0.78, 'massive_boost_37', 'system'),
('INDUSTRY_FOOD: Le marche food delivery FR: 8 milliards € en 2026. Le dark kitchen et le ghost restaurant emergent.', 'Food delivery FR 8 Mds€ 2026. Dark kitchen emerge', NULL, 'insight', 0.78, 'massive_boost_37', 'system'),
('INDUSTRY_GAMING: Le marche gaming FR: 6 milliards € en 2026. L esport et le streaming Twitch/YouTube sont des canaux marketing.', 'Gaming FR 6 Mds€ 2026. Esport + streaming = marketing', NULL, 'insight', 0.75, 'massive_boost_37', 'system'),
('INDUSTRY_MOBILITY: Le marche mobilite douce FR: 3 milliards € en 2026. Les velos electriques et trottinettes dominent.', 'Mobilite douce FR 3 Mds€ 2026. Velos elec + trottinettes', NULL, 'insight', 0.75, 'massive_boost_37', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('STARTUP_PLAYBOOK: Semaine 1-4: valider le probleme (interviews clients). Semaine 5-8: construire le MVP. Semaine 9-12: trouver le PMF.', 'Playbook: S1-4 valider probleme, S5-8 MVP, S9-12 PMF', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('STARTUP_PLAYBOOK: Le pre-launch: construire une audience (newsletter, social) AVANT le lancement du produit.', 'Pre-launch: audience avant produit', 'marketing', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('STARTUP_PLAYBOOK: Les 100 premiers clients sont les plus durs a obtenir. Faire du non-scalable: contacter un par un.', '100 premiers clients: non-scalable, 1 par 1', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('STARTUP_PLAYBOOK: Le feedback des 10 premiers clients vaut plus que 100 sondages. Ecouter intensement.', 'Feedback 10 premiers clients > 100 sondages', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('STARTUP_PLAYBOOK: Le pivot doit etre base sur des donnees (metriques + feedback), pas sur l intuition seule.', 'Pivot: base sur donnees, pas intuition seule', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('CHANNEL_STRATEGY: Le channel-market fit: chaque segment de marche a 1-2 canaux naturels. Trouver et dominer ces canaux.', 'Channel-market fit: 1-2 canaux naturels par segment', 'marketing', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('CHANNEL_STRATEGY: La regle du 70/20/10: 70% du budget sur le canal prouve, 20% sur les canaux en test, 10% sur l exploration.', 'Budget canaux: 70% prouve, 20% test, 10% exploration', 'marketing', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('CHANNEL_STRATEGY: Le word-of-mouth est le canal le plus sous-investi. Investir dans l experience client = investir dans l acquisition.', 'Word-of-mouth sous-investi. Experience client = acquisition', 'marketing', 'insight', 0.85, 'massive_boost_38', 'system'),
('CHANNEL_STRATEGY: Le owned media (blog, newsletter, app) est le seul canal que vous controlez. Les reseaux sociaux peuvent changer les regles.', 'Owned media = seul canal controle. Social peut changer', 'marketing', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('CHANNEL_STRATEGY: Le earned media (PR, mentions, partages) est gratuit mais non controlable. Investir dans les relations presse.', 'Earned media: gratuit mais non controlable. Investir PR', 'marketing', 'insight', 0.80, 'massive_boost_38', 'system'),
('GROWTH_ENGINE: Le acquisition engine: SEO (long terme, scalable) + Paid (court terme, previsible) + Viral (gratuit, imprevisible).', 'Acquisition: SEO long terme + Paid court terme + Viral gratuit', 'marketing', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('GROWTH_ENGINE: Le retention engine: onboarding → education → engagement → expansion → advocacy.', 'Retention: onboarding → education → engagement → expansion → advocacy', 'retention', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('GROWTH_ENGINE: Le monetization engine: freemium → trial → paid → upsell → enterprise.', 'Monetization: freemium → trial → paid → upsell → enterprise', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('GROWTH_ENGINE: Le referral engine: NPS survey → identify promoters → referral program → reward → amplify.', 'Referral: NPS → promoters → program → reward → amplify', 'marketing', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('GROWTH_ENGINE: La growth team ideale: 1 product manager + 1 data analyst + 1 engineer + 1 marketer.', 'Growth team: PM + data + engineer + marketer', 'ceo', 'best_practice', 0.80, 'massive_boost_38', 'system'),
('CONVERSION_COPY: Le headline formula: [Resultat desire] + [Delai] + [Sans obstacle]. Ex: Doublez vos leads en 30 jours sans publicite.', 'Headline: resultat + delai + sans obstacle', 'content', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('CONVERSION_COPY: Le subheadline doit repondre a HOW (comment) si le headline repond a WHAT (quoi).', 'Subheadline = HOW si headline = WHAT', 'content', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('CONVERSION_COPY: Les bullet points de features doivent etre format: Feature + benefice + preuve. Ex: Analytics temps reel → reagissez 10x plus vite (utilise par 500+ startups).', 'Bullet points: feature + benefice + preuve', 'content', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('CONVERSION_COPY: Le CTA button doit dire ce qui se passe apres le clic, pas avant: Recevoir mon guide vs Telecharger.', 'CTA: ce qui se passe apres le clic pas avant', 'content', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('CONVERSION_COPY: La section FAQ en bas de page repond aux dernieres objections et augmente la conversion de 15%.', 'FAQ bas de page = +15% conversion (dernieres objections)', 'content', 'insight', 0.82, 'massive_boost_38', 'system'),
('MONETIZATION: Le freemium-to-paid conversion moyen: 2-5%. Top performers: 10-15%. Le free plan doit creer l habitude.', 'Freemium conversion: 2-5% moyen, 10-15% top', 'ceo', 'insight', 0.85, 'massive_boost_38', 'system'),
('MONETIZATION: Le expansion revenue (upsell + cross-sell) doit representer > 30% de la croissance MRR a maturite.', 'Expansion revenue > 30% croissance MRR mature', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('MONETIZATION: Le net dollar retention (NDR) > 120% signifie que les clients existants generent plus de revenus chaque annee.', 'NDR > 120% = clients generent plus chaque annee', 'ceo', 'insight', 0.85, 'massive_boost_38', 'system'),
('MONETIZATION: Le pricing experiment (tester differents prix sur differents segments) revele le willingness-to-pay reel.', 'Pricing experiment: tester prix sur segments = WTP reel', 'ceo', 'best_practice', 0.80, 'massive_boost_38', 'system'),
('MONETIZATION: Le usage-based pricing (payer selon l utilisation) aligne le cout avec la valeur percue. Ideal pour les APIs.', 'Usage-based pricing = aligner cout + valeur. Ideal APIs', 'ceo', 'insight', 0.82, 'massive_boost_38', 'system'),
('EVENT_DRIVEN: Le trigger marketing (email/notification automatique apres un evenement specifique) a un OR de 45% vs 20% broadcast.', 'Trigger marketing auto = 45% OR vs 20% broadcast', 'email', 'insight', 0.85, 'massive_boost_38', 'system'),
('EVENT_DRIVEN: Les evenements a tracker pour le trigger marketing: signup, first action, inactivity, upgrade, downgrade, churn risk.', 'Trigger events: signup, first action, inactivity, upgrade, downgrade, churn', 'email', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('EVENT_DRIVEN: Le real-time personalization (adapter le contenu du site selon le profil visiteur) augmente la conversion de 20%.', 'Real-time personalization site = +20% conversion', 'marketing', 'insight', 0.80, 'massive_boost_38', 'system'),
('EVENT_DRIVEN: Le lifecycle marketing (adapter le message selon l etape du client) est 5x plus efficace que le broadcast generique.', 'Lifecycle marketing = 5x efficacite vs broadcast', 'email', 'insight', 0.85, 'massive_boost_38', 'system'),
('EVENT_DRIVEN: Le predictive churn alert (IA qui detecte les patterns de desengagement) permet d agir 30 jours avant le churn.', 'Predictive churn IA = agir 30j avant', 'retention', 'insight', 0.82, 'massive_boost_38', 'system'),
('DECISION_FRAMEWORK: Le RICE scoring pour prioriser les features: Reach × Impact × Confidence / Effort. Plus haut = plus prioritaire.', 'RICE: Reach × Impact × Confidence / Effort = prioriser', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('DECISION_FRAMEWORK: Le ICE scoring pour les experiences growth: Impact × Confidence × Ease. Simple et rapide a utiliser.', 'ICE: Impact × Confidence × Ease pour growth experiments', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('DECISION_FRAMEWORK: Le reversibility test: si une decision est facilement reversible, decidez vite. Si irreversible, prenez le temps.', 'Reversibility test: reversible = vite. Irreversible = prendre temps', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('DECISION_FRAMEWORK: Le regret minimization (Jeff Bezos): dans 10 ans, regretterai-je de ne pas avoir essaye?', 'Regret minimization Bezos: regret dans 10 ans?', 'ceo', 'insight', 0.82, 'massive_boost_38', 'system'),
('DECISION_FRAMEWORK: Le 2-way door (decision reversible) vs 1-way door (irreversible): les 2-way doors = decider vite et iterer.', '2-way door = decider vite. 1-way door = reflexion', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('TECH_STACK: Le stack ideal pour un SaaS en 2026: Next.js + Supabase + Vercel + Stripe + Resend + Claude/GPT.', 'Stack SaaS 2026: Next.js + Supabase + Vercel + Stripe + Resend + IA', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('TECH_STACK: Le TypeScript est devenu le standard pour les projets sérieux. Les projets JavaScript pur sont en declin.', 'TypeScript = standard. JavaScript pur en declin', 'ceo', 'insight', 0.85, 'massive_boost_38', 'system'),
('TECH_STACK: Le Tailwind CSS accelere le developpement frontend de 40% et standardise le design system.', 'Tailwind CSS = -40% temps frontend + design system standard', 'ceo', 'insight', 0.82, 'massive_boost_38', 'system'),
('TECH_STACK: Le Supabase est le backend-as-a-service le plus complet: auth + DB + storage + realtime + edge functions.', 'Supabase = backend complet: auth + DB + storage + realtime + edge', 'ceo', 'insight', 0.85, 'massive_boost_38', 'system'),
('TECH_STACK: Le Vercel est la plateforme de deploiement #1 pour Next.js: CI/CD automatique, preview deployments, analytics.', 'Vercel = #1 deploiement Next.js: CI/CD + previews + analytics', 'ceo', 'insight', 0.85, 'massive_boost_38', 'system'),
('PRODUCT_MANAGEMENT: Le PRD (Product Requirements Document) doit contenir: probleme, personas, solution, metriques de succes, timeline.', 'PRD: probleme + personas + solution + metriques + timeline', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('PRODUCT_MANAGEMENT: Le user story format: En tant que [persona], je veux [action] pour [benefice]. Toujours inclure le benefice.', 'User story: En tant que X, je veux Y pour Z', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('PRODUCT_MANAGEMENT: Le sprint de 2 semaines est le rythme ideal pour la majorite des equipes produit.', 'Sprint 2 semaines = rythme ideal', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('PRODUCT_MANAGEMENT: Le definition of done (DoD) doit inclure: code review, tests, documentation, deploy to staging, QA pass.', 'DoD: code review + tests + docs + staging + QA', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('PRODUCT_MANAGEMENT: Le changelog interne (ce qui a ete deploye cette semaine) aligne toute l equipe et motive les developpeurs.', 'Changelog interne hebdo = aligner equipe + motiver devs', 'ceo', 'best_practice', 0.80, 'massive_boost_38', 'system'),
('CUSTOMER_ONBOARDING: Le time-to-value doit etre mesure et optimise. Objectif: < 5 minutes pour un SaaS self-serve.', 'TTV < 5 min SaaS self-serve. Mesurer et optimiser', 'onboarding', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('CUSTOMER_ONBOARDING: Le onboarding checklist visible (progress bar + etapes) augmente la completion de 40%.', 'Onboarding checklist + progress bar = +40% completion', 'onboarding', 'insight', 0.85, 'massive_boost_38', 'system'),
('CUSTOMER_ONBOARDING: Le interactive product tour (tooltips guides) est 3x plus efficace que les tutorials video.', 'Product tour tooltips = 3x vs tutorials video', 'onboarding', 'insight', 0.82, 'massive_boost_38', 'system'),
('CUSTOMER_ONBOARDING: Le personalized onboarding (adapter le parcours au role/objectif) augmente l activation de 30%.', 'Onboarding personnalise role/objectif = +30% activation', 'onboarding', 'insight', 0.85, 'massive_boost_38', 'system'),
('CUSTOMER_ONBOARDING: Le lifecycle email onboarding: welcome J0, quick win J1, cas client J3, feature avancee J5, recap J7, upgrade J14.', 'Email onboarding lifecycle: J0→J1→J3→J5→J7→J14', 'onboarding', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('API_DESIGN: Les API RESTful doivent suivre les conventions: GET (lire), POST (creer), PUT (remplacer), PATCH (modifier), DELETE (supprimer).', 'REST: GET lire, POST creer, PUT remplacer, PATCH modifier, DELETE supprimer', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('API_DESIGN: La pagination des API (limit/offset ou cursor-based) est obligatoire pour les listes. Jamais retourner toute la collection.', 'API pagination obligatoire. Jamais retourner tout', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('API_DESIGN: Le rate limiting (429 Too Many Requests) protege l API contre les abus et les erreurs de boucle infinie.', 'Rate limiting 429 = protection abus + boucles infinies', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('API_DESIGN: La versioning d API (v1, v2) permet d evoluer sans casser les integrations existantes.', 'API versioning v1/v2 = evoluer sans casser integrations', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('API_DESIGN: Les error messages API doivent etre descriptifs: { error: message, code: ERR_CODE, details: ... }. Pas juste Internal Error.', 'API errors descriptifs: message + code + details', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('TESTING_CODE: Les tests unitaires couvrent les fonctions individuelles. Les tests d integration couvrent les interactions entre services.', 'Tests unitaires = fonctions. Integration = interactions services', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('TESTING_CODE: Le code coverage ideal: > 80% pour le code business-critical, > 60% pour le reste. 100% n est pas necessaire.', 'Code coverage: >80% critical, >60% reste. 100% pas necessaire', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('TESTING_CODE: Le test pyramid: beaucoup de tests unitaires (rapides), quelques tests d integration, peu de tests E2E (lents).', 'Test pyramid: unit (beaucoup) > integration > E2E (peu)', 'ceo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('TESTING_CODE: Le CI pipeline doit executer les tests avant chaque merge. Si un test echoue, le merge est bloque.', 'CI: tests avant merge. Echec = merge bloque', 'ceo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('TESTING_CODE: Le load testing (simuler X users simultanement) doit etre fait avant tout lancement ou pic prevu.', 'Load testing: simuler users avant lancement/pic', 'ceo', 'best_practice', 0.82, 'massive_boost_38', 'system'),
('ACCESSIBILITY_WEB: Le contraste texte/fond minimum: 4.5:1 pour le texte normal, 3:1 pour le grand texte (WCAG AA).', 'Contraste WCAG AA: 4.5:1 normal, 3:1 grand texte', 'seo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('ACCESSIBILITY_WEB: Les images doivent avoir un alt text descriptif. Les images decoratives alt="" (vide).', 'Alt text: descriptif pour info, vide pour decoratif', 'seo', 'best_practice', 0.88, 'massive_boost_38', 'system'),
('ACCESSIBILITY_WEB: La navigation au clavier (tab, enter, escape) doit fonctionner pour tous les elements interactifs.', 'Navigation clavier obligatoire pour elements interactifs', 'seo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('ACCESSIBILITY_WEB: Les formulaires doivent avoir des labels visibles (pas juste des placeholders) pour l accessibilite.', 'Formulaires: labels visibles, pas juste placeholders', 'seo', 'best_practice', 0.85, 'massive_boost_38', 'system'),
('ACCESSIBILITY_WEB: Le ARIA (Accessible Rich Internet Applications) ameliore l experience des lecteurs d ecran.', 'ARIA = ameliorer experience lecteurs ecran', 'seo', 'best_practice', 0.82, 'massive_boost_38', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MARKETING_AUTOMATION: Le marketing automation reduit le cout par lead de 33% et augmente la qualite des leads de 50%.', 'Marketing auto: -33% CPL +50% qualite leads', 'marketing', 'insight', 0.85, 'massive_boost_39', 'system'),
('MARKETING_AUTOMATION: Le workflow le plus rentable: nouveau lead → scoring → segmentation → nurturing → MQL → handoff sales.', 'Workflow auto: lead → score → segment → nurture → MQL → sales', 'marketing', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('MARKETING_AUTOMATION: L automation sans strategie est du spam automatise. Toujours definir les objectifs et les segments avant.', 'Automation sans strategie = spam auto. Objectifs + segments d abord', 'marketing', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('MARKETING_AUTOMATION: Le progressive profiling (collecter 1-2 infos par interaction) remplit le profil sans friction.', 'Progressive profiling: 1-2 infos/interaction = profil sans friction', 'marketing', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('MARKETING_AUTOMATION: Les workflows automatises doivent etre revus chaque mois. Les sequences obsoletes font plus de mal que de bien.', 'Revoir workflows auto chaque mois. Obsoletes = nuisibles', 'marketing', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('LOCAL_BUSINESS: Les commerces locaux qui utilisent Google Business Messages voient 30% d appels supplementaires.', 'Google Business Messages local = +30% appels', 'gmaps', 'insight', 0.80, 'massive_boost_39', 'system'),
('LOCAL_BUSINESS: Le geotargeting publicitaire dans un rayon de 5km convertit 3x mieux que le ciblage national.', 'Geotargeting 5km = 3x conversion vs national', 'ads', 'insight', 0.82, 'massive_boost_39', 'system'),
('LOCAL_BUSINESS: Les events in-store (ateliers, degustations, lancements) generent du UGC gratuit et du bouche-a-oreille.', 'Events in-store = UGC gratuit + bouche-a-oreille', NULL, 'insight', 0.80, 'massive_boost_39', 'system'),
('LOCAL_BUSINESS: Le parrainage local (1 client amene 1 client) est le canal #1 d acquisition pour les commerces de proximite.', 'Parrainage local = canal #1 commerces proximite', NULL, 'best_practice', 0.85, 'massive_boost_39', 'system'),
('LOCAL_BUSINESS: La fidelisation par SMS (offre anniversaire, happy hour, nouveau produit) a un taux de lecture de 95%.', 'SMS fidelisation local = 95% lecture', NULL, 'insight', 0.82, 'massive_boost_39', 'system'),
('B2B_CONTENT: Le white paper (10-20 pages de recherche) est le lead magnet #1 pour les decision-makers B2B.', 'White paper 10-20p = lead magnet #1 decision-makers B2B', 'content', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('B2B_CONTENT: Le webinaire B2B ideal: 30 min de contenu + 15 min de Q&A. Au-dela de 60 min les participants decrochent.', 'Webinaire B2B: 30 min contenu + 15 min Q&A. Max 60 min', 'content', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('B2B_CONTENT: Les benchmark reports (donnees du secteur) sont les contenus les plus telecharges et partages en B2B.', 'Benchmark reports = plus telecharges et partages B2B', 'content', 'insight', 0.82, 'massive_boost_39', 'system'),
('B2B_CONTENT: Les customer success stories doivent suivre le format: challenge → solution → resultats chiffres → quote client.', 'Success story B2B: challenge → solution → resultats → quote', 'content', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('B2B_CONTENT: Le ROI content (montrer le retour financier concret) est le contenu le plus persuasif pour les CFO/CEO.', 'ROI content = plus persuasif pour CFO/CEO', 'content', 'insight', 0.85, 'massive_boost_39', 'system'),
('PERSONAL_PRODUCTIVITY: Le morning routine (routine matinale structuree) augmente la productivite de la journee de 25%.', 'Morning routine = +25% productivite journee', 'rh', 'insight', 0.78, 'massive_boost_39', 'system'),
('PERSONAL_PRODUCTIVITY: Le eat the frog (faire la tache la plus difficile en premier) maximise la productivite quotidienne.', 'Eat the frog: tache difficile en premier = max productivite', 'rh', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('PERSONAL_PRODUCTIVITY: Le single-tasking (1 tache a la fois) est 40% plus productif que le multitasking.', 'Single-tasking = +40% productivite vs multitasking', 'rh', 'insight', 0.82, 'massive_boost_39', 'system'),
('PERSONAL_PRODUCTIVITY: Le weekly review (revue hebdomadaire de 30 min) aligne la semaine suivante avec les objectifs.', 'Weekly review 30 min = aligner semaine avec objectifs', 'rh', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('PERSONAL_PRODUCTIVITY: Le energy management (travailler selon ses pics d energie, pas l horloge) augmente la qualite du travail de 30%.', 'Energy management: pics energie > horloge = +30% qualite', 'rh', 'insight', 0.78, 'massive_boost_39', 'system'),
('LANDING_PAGE_TIPS: Le hero image doit montrer le resultat (pas le produit). Le client veut voir ou il va, pas l outil.', 'Hero image: montrer resultat pas produit', 'commercial', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('LANDING_PAGE_TIPS: Les logos clients (social proof) augmentent la credibilite de 30%. Minimum 5 logos reconnaissables.', 'Logos clients 5+ = +30% credibilite landing', 'commercial', 'insight', 0.82, 'massive_boost_39', 'system'),
('LANDING_PAGE_TIPS: Le scroll depth moyen sur une landing page: 50-60%. Les infos cruciales doivent etre dans la premiere moitie.', 'Scroll depth landing 50-60%. Infos cruciales dans premiere moitie', 'commercial', 'insight', 0.82, 'massive_boost_39', 'system'),
('LANDING_PAGE_TIPS: Le nombre d or des CTAs: 1 CTA principal repete 3 fois (hero, milieu, bottom). Pas de CTAs competiteurs.', 'CTA: 1 principal repete 3x. Pas de CTAs competiteurs', 'commercial', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('LANDING_PAGE_TIPS: Le video background hero (sans son, en boucle) augmente le temps sur page de 88% mais peut ralentir le chargement.', 'Video background hero = +88% temps page. Attention vitesse', 'commercial', 'insight', 0.78, 'massive_boost_39', 'system'),
('REPORTING: Le reporting quotidien doit tenir en 5 lignes: hier, aujourd hui, blocages, metriques cles, decisions.', 'Reporting quotidien: 5 lignes max. Hier/aujourd hui/blocages/metriques/decisions', 'ceo', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('REPORTING: Le dashboard C-level doit avoir max 5 KPIs: MRR, growth rate, churn, NPS, runway.', 'Dashboard C-level: 5 KPIs max = MRR, growth, churn, NPS, runway', 'ceo', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('REPORTING: Le monthly business review (MBR) de 60 min aligne toute l equipe: performances, learnings, plan du mois suivant.', 'MBR mensuel 60 min: perfs + learnings + plan mois suivant', 'ceo', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('REPORTING: Les metriques doivent etre comparees au mois precedent ET a l annee precedente pour detecter les tendances.', 'Metriques: comparer mois-1 ET annee-1 pour tendances', 'ceo', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('REPORTING: Le traffic light system (vert/jaune/rouge) pour les KPIs permet de voir l etat de sante en 1 seconde.', 'Traffic light KPIs: vert/jaune/rouge = sante en 1s', 'ceo', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('FEEDBACK_LOOP: Le feedback continu (pas annuel) ameliore la performance de 12% et reduit le turnover de 14%.', 'Feedback continu = +12% performance -14% turnover', 'rh', 'insight', 0.82, 'massive_boost_39', 'system'),
('FEEDBACK_LOOP: Le format SBI (Situation, Behavior, Impact) rend le feedback specifique et actionable.', 'Feedback SBI: Situation, Behavior, Impact = specifique', 'rh', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('FEEDBACK_LOOP: Le feedforward (suggerer ce qu il faut faire au lieu de critiquer ce qui a ete fait) est plus constructif.', 'Feedforward > feedback: suggerer futur vs critiquer passe', 'rh', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('FEEDBACK_LOOP: Le 360 feedback (feedback de tous les angles: manager, peers, reports) donne une vue complete.', '360 feedback: manager + peers + reports = vue complete', 'rh', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('FEEDBACK_LOOP: Le radical candor (etre direct et bienveillant) est le style de feedback le plus efficace (Kim Scott).', 'Radical candor: direct + bienveillant = plus efficace', 'rh', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('SOCIAL_PROOF_TYPES: Le proof by numbers: 10 000+ clients satisfaits, 99.9% uptime, 4.8/5 sur G2.', 'Proof by numbers: clients + uptime + ratings', 'commercial', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('SOCIAL_PROOF_TYPES: Le proof by authority: vu dans Forbes, recommande par [expert connu], partenaire de [marque].', 'Proof by authority: presse + experts + partenaires', 'commercial', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('SOCIAL_PROOF_TYPES: Le proof by peers: temoignages de clients similaires au prospect (meme taille, secteur, probleme).', 'Proof by peers: temoignages clients similaires prospect', 'commercial', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('SOCIAL_PROOF_TYPES: Le proof by certification: SOC 2, RGPD compliant, ISO 27001, HIPAA (selon le secteur).', 'Proof by certification: SOC2, RGPD, ISO 27001, HIPAA', 'commercial', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('SOCIAL_PROOF_TYPES: Le proof by results: avant/apres chiffre, ROI mesure, economies realisees.', 'Proof by results: avant/apres + ROI + economies', 'commercial', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('ECOSYSTEM: Les integrations avec les outils populaires (Slack, Zapier, HubSpot) augmentent l adoption de 25%.', 'Integrations populaires = +25% adoption', 'ceo', 'insight', 0.82, 'massive_boost_39', 'system'),
('ECOSYSTEM: Le marketplace d integrations (comme Shopify Apps) cree un ecosysteme qui renforce le moat.', 'Marketplace integrations = ecosysteme + moat', 'ceo', 'insight', 0.80, 'massive_boost_39', 'system'),
('ECOSYSTEM: Les partenaires d implementation (agences, consultants) sont un canal de distribution scalable.', 'Partenaires implementation = canal distribution scalable', 'ceo', 'insight', 0.80, 'massive_boost_39', 'system'),
('ECOSYSTEM: L open API attire les developpeurs et cree des integrations que l equipe n aurait pas construites.', 'Open API = attirer devs + integrations inattendues', 'ceo', 'insight', 0.80, 'massive_boost_39', 'system'),
('ECOSYSTEM: Les certifications partenaires (certified partner program) creent un reseau de vente indirecte.', 'Certified partner program = vente indirecte', 'ceo', 'insight', 0.78, 'massive_boost_39', 'system'),
('COPYWRITING_FR: Le tutoiement en marketing B2C francais est accepte pour les marques lifestyle, tech, et jeunes.', 'Tutoiement FR B2C: lifestyle, tech, jeune = accepte', 'content', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('COPYWRITING_FR: Les expressions franglaises (growth hacking, mindset, workflow) sont acceptees en tech mais eviter en B2C grand public.', 'Franglais: ok tech, eviter B2C grand public', 'content', 'best_practice', 0.80, 'massive_boost_39', 'system'),
('COPYWRITING_FR: Le humour francais (ironie, understatement) fonctionne mieux que l humour anglo-saxon (exageration, enthousiasme).', 'Humour FR: ironie/understatement > exageration/enthousiasme', 'content', 'insight', 0.78, 'massive_boost_39', 'system'),
('COPYWRITING_FR: Les Francais sont mefiants face au marketing agressif. Preferer la subtilite et la preuve a la promesse grandiloquente.', 'FR mefiants marketing agressif. Subtilite + preuve > promesse', 'content', 'insight', 0.82, 'massive_boost_39', 'system'),
('COPYWRITING_FR: Le storytelling personnel (fondateur, equipe, parcours) resonne fort avec le public francais qui valorise l authenticite.', 'Storytelling perso FR: fondateur/equipe/parcours = authenticite', 'content', 'insight', 0.82, 'massive_boost_39', 'system'),
('FINANCIAL_MODEL: Le model SaaS: MRR × 12 × growth rate × gross margin = indicateur de valorisation.', 'Model SaaS: MRR × 12 × growth × gross margin = valorisation', 'comptable', 'insight', 0.80, 'massive_boost_39', 'system'),
('FINANCIAL_MODEL: Le rule of 40 (growth rate + profit margin > 40%) est utilise par les investisseurs pour evaluer les SaaS.', 'Rule of 40: growth + profit > 40% pour investisseurs', 'comptable', 'insight', 0.85, 'massive_boost_39', 'system'),
('FINANCIAL_MODEL: Le LTV/CAC ratio doit etre > 3 pour un business sain. < 1 = on perd de l argent par client.', 'LTV/CAC > 3 sain. < 1 = perte par client', 'comptable', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('FINANCIAL_MODEL: Le payback period (mois pour recuperer le CAC) doit etre < 12 mois. Idealement < 6 mois.', 'Payback period < 12 mois. Ideal < 6 mois', 'comptable', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('FINANCIAL_MODEL: Le scenario planning (optimiste, realiste, pessimiste) prepare aux differentes trajectoires possibles.', 'Scenario planning: optimiste + realiste + pessimiste', 'comptable', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('LEGAL_TIPS: Les CGU SaaS doivent inclure: clause de responsabilite limitee, propriete des donnees, politique de suppression.', 'CGU SaaS: responsabilite limitee, propriete data, suppression', 'ceo', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('LEGAL_TIPS: Le DPA (Data Processing Agreement) est obligatoire pour tout sous-traitant qui accede aux donnees personnelles.', 'DPA obligatoire sous-traitants donnees personnelles', 'ceo', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('LEGAL_TIPS: Le contrat freelance/prestataire doit inclure: livrables, delais, prix, PI, confidentialite, resiliation.', 'Contrat freelance: livrables, delais, prix, PI, confidentialite, resiliation', 'ceo', 'best_practice', 0.82, 'massive_boost_39', 'system'),
('LEGAL_TIPS: La marque doit etre deposee avant le lancement public. INPI en France, EUIPO en Europe, USPTO aux USA.', 'Deposer marque avant lancement: INPI FR, EUIPO EU, USPTO US', 'ceo', 'best_practice', 0.85, 'massive_boost_39', 'system'),
('LEGAL_TIPS: Les cookies non essentiels (analytics, marketing) necessitent le consentement explicite en Europe (ePrivacy).', 'Cookies non essentiels: consentement explicite EU (ePrivacy)', 'ceo', 'best_practice', 0.88, 'massive_boost_39', 'system'),
('HIRING: Le test de culture (diner, cafe informel) est le meilleur predictor de compatibilite equipe.', 'Test culture (diner/cafe) = meilleur predictor compatibilite', 'rh', 'best_practice', 0.78, 'massive_boost_39', 'system'),
('HIRING: Le take-home assignment (exercice pratique de 2-3h) est plus predictif qu un entretien classique de 45 min.', 'Take-home assignment 2-3h > entretien 45 min pour prediction', 'rh', 'insight', 0.80, 'massive_boost_39', 'system'),
('HIRING: La structured interview (memes questions pour tous les candidats) est 2x plus predictive que l entretien non structure.', 'Structured interview = 2x plus predictive vs non structuree', 'rh', 'insight', 0.82, 'massive_boost_39', 'system'),
('HIRING: Le employer brand sur LinkedIn et Glassdoor impacte 75% des candidats dans leur decision de postuler.', 'Employer brand LinkedIn/Glassdoor = 75% candidats influences', 'rh', 'insight', 0.82, 'massive_boost_39', 'system'),
('HIRING: Le counter-offer (contre-offre quand un employe veut partir) ne marche que dans 20% des cas. Mieux vaut investir en prevention.', 'Counter-offer: 20% efficacite. Mieux = prevention', 'rh', 'insight', 0.78, 'massive_boost_39', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('VIRAL_MECHANICS: Le emotional resonance (contenu qui declenche une emotion forte) est partage 7x plus que le contenu neutre.', 'Emotional resonance = 7x partages vs neutre', 'content', 'insight', 0.85, 'massive_boost_40', 'system'),
('VIRAL_MECHANICS: Le identity signaling (partager pour montrer qui on est) est le moteur #1 du partage social.', 'Identity signaling = moteur #1 partage social', 'content', 'insight', 0.82, 'massive_boost_40', 'system'),
('VIRAL_MECHANICS: Le practical value (contenu utile et actionable) est le 2e moteur de partage. Les gens veulent aider leur reseau.', 'Practical value = moteur #2 partage. Aider son reseau', 'content', 'insight', 0.82, 'massive_boost_40', 'system'),
('VIRAL_MECHANICS: Le social currency (contenu qui fait paraitre intelligent, drole, ou connecte) motive 30% des partages.', 'Social currency = 30% motivation partage', 'content', 'insight', 0.80, 'massive_boost_40', 'system'),
('VIRAL_MECHANICS: Le trigger (associer le contenu a un moment quotidien) augmente le partage recurrent. Ex: KitKat = pause cafe.', 'Trigger quotidien = partage recurrent. Ex: KitKat = pause', 'marketing', 'insight', 0.78, 'massive_boost_40', 'system'),
('CONVERSION_TRIGGERS: L urgence reelle (offre expire dans 48h) augmente les conversions de 332%. Jamais de fake urgence.', 'Urgence reelle 48h = +332% conversions. Jamais fake', 'commercial', 'insight', 0.85, 'massive_boost_40', 'system'),
('CONVERSION_TRIGGERS: La rarete reelle (plus que 5 places) augmente les inscriptions de 40%. La rarete doit etre vraie.', 'Rarete reelle 5 places = +40% inscriptions. Doit etre vraie', 'commercial', 'insight', 0.82, 'massive_boost_40', 'system'),
('CONVERSION_TRIGGERS: L exclusivite (sur invitation, beta privee, VIP) cree de la desirabilite et du FOMO positif.', 'Exclusivite invitation/beta/VIP = desirabilite + FOMO', 'marketing', 'insight', 0.82, 'massive_boost_40', 'system'),
('CONVERSION_TRIGGERS: La gratuite conditionnelle (gratuit si vous faites X) combine la valeur percue et l engagement actif.', 'Gratuite conditionnelle = valeur percue + engagement actif', 'marketing', 'insight', 0.78, 'massive_boost_40', 'system'),
('CONVERSION_TRIGGERS: Le free trial est le trigger de conversion #1 pour les SaaS. 14 jours est la duree standard.', 'Free trial 14j = trigger conversion #1 SaaS', 'ceo', 'best_practice', 0.88, 'massive_boost_40', 'system'),
('SALES_METHODOLOGY: Le MEDDIC (Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, Champion) qualifie les deals B2B.', 'MEDDIC: Metrics, Economic buyer, Decision, Pain, Champion', 'commercial', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('SALES_METHODOLOGY: Le Sandler (upfront contract, budget, decision process, presentation, post-sell) est ideal pour les ventes consultatives.', 'Sandler: ideal ventes consultatives B2B', 'commercial', 'best_practice', 0.80, 'massive_boost_40', 'system'),
('SALES_METHODOLOGY: Le Solution Selling (diagnostiquer avant de prescrire) est le framework le plus adapte aux SaaS complexes.', 'Solution Selling: diagnostiquer avant prescrire = SaaS complexes', 'commercial', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('SALES_METHODOLOGY: Le value selling (vendre la valeur business, pas les features) augmente la taille des deals de 30%.', 'Value selling: valeur business > features = +30% deal size', 'commercial', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('SALES_METHODOLOGY: Le consultative selling (devenir un conseiller de confiance) genere 5x plus de referrals que le transactional selling.', 'Consultative selling = 5x referrals vs transactional', 'commercial', 'insight', 0.82, 'massive_boost_40', 'system'),
('STARTUP_CULTURE: La transparence radicale (partager les chiffres, les decisions, les echecs avec toute l equipe) cree la confiance.', 'Transparence radicale: chiffres + decisions + echecs = confiance equipe', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('STARTUP_CULTURE: La velocite (agir vite et iterer) est le seul avantage d une startup face aux grandes entreprises.', 'Velocite = seul avantage startup vs grandes entreprises', 'ceo', 'insight', 0.88, 'massive_boost_40', 'system'),
('STARTUP_CULTURE: Le biais pour l action (80% d info suffit pour decider) previent la paralysie analytique.', 'Biais pour action: 80% info = decider. Eviter paralysie', 'ceo', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('STARTUP_CULTURE: Le ownership (chaque personne est responsable de son domaine) cree l autonomie et la motivation.', 'Ownership par domaine = autonomie + motivation', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('STARTUP_CULTURE: Le learning culture (encourager l apprentissage et l experimentation) cree l innovation continue.', 'Learning culture = innovation continue', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('B2C_MARKETING: Le impulse purchase (achat impulsif) represente 40% des depenses en ligne. Simplifier le parcours d achat.', 'Achat impulsif = 40% depenses online. Simplifier parcours', NULL, 'insight', 0.82, 'massive_boost_40', 'system'),
('B2C_MARKETING: Le seasonal marketing (adapter les campagnes aux saisons) augmente les ventes de 15% vs le marketing constant.', 'Seasonal marketing = +15% ventes vs constant', 'marketing', 'insight', 0.80, 'massive_boost_40', 'system'),
('B2C_MARKETING: Les unboxing videos (YouTube/TikTok) generent du trafic gratuit et du desir pour les produits physiques.', 'Unboxing videos = trafic gratuit + desir produits physiques', NULL, 'insight', 0.80, 'massive_boost_40', 'system'),
('B2C_MARKETING: Le loyalty program avec tiers (bronze/silver/gold) augmente les depenses de 20% pour atteindre le tier suivant.', 'Loyalty tiers bronze/silver/gold = +20% depenses pour tier suivant', NULL, 'insight', 0.82, 'massive_boost_40', 'system'),
('B2C_MARKETING: Le surprise & delight (cadeau inattendu, note personnelle) cree des moments Instagram-worthy et du UGC.', 'Surprise & delight = moments Instagram-worthy + UGC', NULL, 'insight', 0.80, 'massive_boost_40', 'system'),
('INNOVATION_PROCESS: Le design sprint (5 jours: comprendre, ideate, decider, prototyper, tester) valide une idee en 1 semaine.', 'Design sprint 5j: comprendre → ideate → decider → prototype → test', 'ceo', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('INNOVATION_PROCESS: Le pre-mortem (imaginer l echec avant de lancer) identifie les risques que l optimisme cache.', 'Pre-mortem: imaginer echec = identifier risques caches', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('INNOVATION_PROCESS: Le assumption mapping (lister et tester les hypotheses les plus risquees en premier) reduit le gaspillage.', 'Assumption mapping: tester hypotheses risquees d abord', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('INNOVATION_PROCESS: Le fake door test (creer un CTA pour une feature qui n existe pas encore et mesurer les clics) valide la demande.', 'Fake door test: CTA feature inexistante = valider demande', 'ceo', 'best_practice', 0.80, 'massive_boost_40', 'system'),
('INNOVATION_PROCESS: Le painted door test (proposer l option dans l UI sans la construire) mesure l interet reel des users.', 'Painted door test: option UI non construite = mesurer interet', 'ceo', 'best_practice', 0.80, 'massive_boost_40', 'system'),
('CUSTOMER_ADVOCACY: Les clients promoteurs (NPS 9-10) sont prets a recommander. Les activer avec un programme de parrainage.', 'NPS 9-10 = promoteurs. Activer avec programme parrainage', 'retention', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('CUSTOMER_ADVOCACY: Le customer story program (collecter et publier les histoires de succes) est le meilleur contenu marketing.', 'Customer story program = meilleur contenu marketing', 'content', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('CUSTOMER_ADVOCACY: Le customer advisory board (10 meilleurs clients) informe le roadmap et cree des ambassadeurs ultra-loyaux.', 'Customer advisory board 10 meilleurs = roadmap + ambassadeurs', 'retention', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('CUSTOMER_ADVOCACY: Le G2/Capterra review drive (email systematique pour demander un avis) augmente les reviews de 500%.', 'Review drive G2/Capterra email systematique = +500% reviews', 'marketing', 'insight', 0.80, 'massive_boost_40', 'system'),
('CUSTOMER_ADVOCACY: Le user conference annuel (meme virtuel) cree un sentiment de communaute et renforce la loyalty.', 'User conference annuel = communaute + loyalty', 'marketing', 'insight', 0.78, 'massive_boost_40', 'system'),
('REVENUE_OPS: Le RevOps (aligner marketing + sales + CS sur les memes metriques) augmente le revenu de 19%.', 'RevOps: aligner marketing + sales + CS = +19% revenu', 'ceo', 'insight', 0.82, 'massive_boost_40', 'system'),
('REVENUE_OPS: Le single source of truth (CRM partage entre marketing, vente et CS) elimine les silos et les pertes d info.', 'CRM partage marketing+vente+CS = 0 silos', 'ceo', 'best_practice', 0.85, 'massive_boost_40', 'system'),
('REVENUE_OPS: Le SLA entre marketing et ventes (marketing livre X MQLs, ventes les contacte en < 24h) augmente la conversion de 30%.', 'SLA marketing→ventes MQLs <24h = +30% conversion', 'commercial', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('REVENUE_OPS: Le closed-loop reporting (suivre un lead de la premiere visite jusqu a la vente) revele les vrais canaux performants.', 'Closed-loop reporting: lead premiere visite → vente = vrais canaux', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('REVENUE_OPS: Le tech stack RevOps ideal: CRM (HubSpot/Salesforce) + automation (Zapier) + analytics (GA4+Mixpanel) + enrichment (Clearbit).', 'Tech stack RevOps: CRM + automation + analytics + enrichment', 'ceo', 'best_practice', 0.80, 'massive_boost_40', 'system'),
('METRICS_FRAMEWORK: Le AARRR (Acquisition, Activation, Retention, Revenue, Referral) est le framework metrics le plus utilise en startup.', 'AARRR: Acquisition, Activation, Retention, Revenue, Referral', 'ceo', 'best_practice', 0.88, 'massive_boost_40', 'system'),
('METRICS_FRAMEWORK: Le north star metric pour KeiroAI: nombre d actions d agents executees avec succes par semaine.', 'North star KeiroAI: actions agents reussies/semaine', 'ceo', 'best_practice', 0.90, 'massive_boost_40', 'system'),
('METRICS_FRAMEWORK: Le input metrics (actions controlables) vs output metrics (resultats). Focus sur les inputs car ils sont actionnables.', 'Input metrics (actions) > output metrics (resultats). Focus inputs', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('METRICS_FRAMEWORK: Le leading indicators (predictifs: signup rate) vs lagging indicators (resultats: churn). Tracker les deux.', 'Leading (signup rate) vs lagging (churn). Tracker les 2', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('METRICS_FRAMEWORK: Le OKR cadence: objectifs trimestriels, key results hebdomadaires, review mensuelle.', 'OKR: objectifs trimestriels, KR hebdo, review mensuelle', 'ceo', 'best_practice', 0.82, 'massive_boost_40', 'system'),
('ECOSYSTEM_FR: Les accelerateurs francais (Station F, TheFamily, Techstars Paris) offrent reseau + mentorat + parfois financement.', 'Accelerateurs FR: Station F, TheFamily, Techstars = reseau + mentorat', 'ceo', 'insight', 0.78, 'massive_boost_40', 'system'),
('ECOSYSTEM_FR: Les concours startups (BPI France, FrenchTech, CES Innovation Awards) offrent visibilite + financement.', 'Concours startups FR: BPI, FrenchTech, CES = visibilite + financement', 'ceo', 'insight', 0.78, 'massive_boost_40', 'system'),
('ECOSYSTEM_FR: Le label French Tech est un atout pour l international. Il signale l innovation et la qualite technique francaise.', 'Label French Tech = atout international. Innovation + qualite', 'ceo', 'insight', 0.78, 'massive_boost_40', 'system'),
('ECOSYSTEM_FR: Le reseau des CCI (Chambres de Commerce) offre des formations et un accompagnement gratuit aux entrepreneurs.', 'CCI: formations + accompagnement gratuit entrepreneurs', 'ceo', 'insight', 0.78, 'massive_boost_40', 'system'),
('ECOSYSTEM_FR: Les French Tech Communautes (dans chaque ville) organisent des events et du networking local.', 'French Tech Communautes: events + networking local', 'ceo', 'insight', 0.75, 'massive_boost_40', 'system'),
('FINAL_WISDOM: Le succes n est pas lineaire. Les startups qui reussissent ont traverse des moments ou tout semblait perdu.', 'Succes non lineaire. Moments sombres = normal', 'ceo', 'insight', 0.85, 'massive_boost_40', 'system'),
('FINAL_WISDOM: La persistence est le facteur #1 de succes entrepreneurial. Les plus persistants finissent par trouver le chemin.', 'Persistence = facteur #1 succes entrepreneurial', 'ceo', 'insight', 0.88, 'massive_boost_40', 'system'),
('FINAL_WISDOM: Le client a toujours raison sur le PROBLEME. Pas toujours sur la SOLUTION. Ecouter le probleme, proposer la solution.', 'Client raison sur probleme, pas solution. Ecouter + proposer', 'ceo', 'best_practice', 0.88, 'massive_boost_40', 'system'),
('FINAL_WISDOM: La simplicite est la sophistication supreme (Leonardo da Vinci). Le produit le plus simple qui resout le probleme gagne.', 'Simplicite = sophistication supreme. Plus simple = gagne', 'ceo', 'insight', 0.88, 'massive_boost_40', 'system'),
('FINAL_WISDOM: Les fondateurs qui prennent soin de leur sante mentale et physique ont 2x plus de chances de reussir a long terme.', 'Sante mentale + physique fondateur = 2x chances succes long terme', 'ceo', 'insight', 0.82, 'massive_boost_40', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ADVANCED_GROWTH: Le PLG flywheel: free users → power users → teams → enterprise. Chaque etape alimente la suivante.', 'PLG flywheel: free → power → teams → enterprise', 'ceo', 'best_practice', 0.85, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le bottoms-up adoption (un employe adopte, puis l equipe, puis l entreprise) est la croissance PLG ideale.', 'Bottoms-up adoption: employe → equipe → entreprise', 'ceo', 'insight', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le time-to-wow (temps avant que le client dise wow) doit etre < 30 secondes pour les apps consumer.', 'Time-to-wow < 30s apps consumer', 'onboarding', 'best_practice', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le activation metric (la mesure specifique du aha moment) varie par produit. Pour KeiroAI: premier agent qui produit un resultat.', 'Activation metric KeiroAI: premier agent → resultat', 'onboarding', 'best_practice', 0.90, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le habit loop (cue → routine → reward) doit etre design dans le produit pour creer l usage quotidien.', 'Habit loop: cue → routine → reward = usage quotidien', 'retention', 'best_practice', 0.82, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le network effect direct: plus d utilisateurs = plus de valeur pour chaque utilisateur (ex: marketplace).', 'Network effect direct: plus users = plus valeur/user', 'ceo', 'insight', 0.85, 'massive_boost_51', 'system'),
('ADVANCED_GROWTH: Le data network effect: plus d utilisateurs = plus de donnees = meilleur produit = plus d utilisateurs.', 'Data network effect: users → data → meilleur produit → users', 'ceo', 'insight', 0.85, 'massive_boost_51', 'system'),
('PRICING_MODEL: Le seat-based pricing (par utilisateur) est le plus previsible pour le client et le plus simple a comprendre.', 'Seat-based pricing = previsible + simple', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le usage-based pricing (pay-as-you-go) aligne le prix avec la valeur percue. Ideal pour les APIs et infrastructures.', 'Usage-based = aligner prix/valeur. Ideal APIs/infra', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le tiered pricing (plans par niveau) est le plus courant pour les SaaS. 3-4 tiers est optimal.', 'Tiered pricing SaaS: 3-4 plans optimal', 'ceo', 'best_practice', 0.85, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le flat-rate pricing (prix unique) est le plus simple mais ne capture pas la valeur des gros clients.', 'Flat-rate: simple mais ne capture pas valeur gros clients', 'ceo', 'insight', 0.80, 'massive_boost_52', 'system'),
('PRICING_MODEL: Le hybrid pricing (base fixe + usage variable) combine previsibilite et alignement avec la valeur.', 'Hybrid pricing: base fixe + usage variable = previsible + aligne', 'ceo', 'insight', 0.82, 'massive_boost_52', 'system'),
('CUSTOMER_INTERVIEW: Les 5 questions essentielles: quel probleme?, comment le resolvez-vous?, qu est-ce qui ne fonctionne pas?, budget?, timeline?', 'Interview client: probleme? resolution? blocage? budget? timeline?', 'commercial', 'best_practice', 0.85, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Le Mom Test (Rob Fitzpatrick): poser des questions sur le comportement passe, pas sur les opinions futures.', 'Mom Test: questions comportement passe, pas opinions futures', 'ceo', 'best_practice', 0.88, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Ne jamais demander si le client acheterait votre produit. Observer ce qu il fait, pas ce qu il dit.', 'Ne pas demander si acheterait. Observer les actions', 'ceo', 'best_practice', 0.88, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: 10 interviews suffisent pour trouver des patterns. Si les 10 disent la meme chose, c est un signal fort.', '10 interviews = patterns. Meme reponse 10x = signal fort', 'ceo', 'insight', 0.85, 'massive_boost_53', 'system'),
('CUSTOMER_INTERVIEW: Les questions follow-up (pourquoi? pouvez-vous me donner un exemple?) revelent les insights profonds.', 'Questions follow-up pourquoi/exemple = insights profonds', 'ceo', 'best_practice', 0.85, 'massive_boost_53', 'system'),
('SEO_ADVANCED: Le topical map (cartographie de tous les sujets a couvrir) structure la strategie de contenu SEO sur 12 mois.', 'Topical map = strategie contenu SEO 12 mois', 'seo', 'best_practice', 0.85, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le link building par la creation de contenu remarquable (etudes, outils gratuits, infographies) est la methode la plus durable.', 'Link building par contenu remarquable = plus durable', 'seo', 'best_practice', 0.85, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le internal link audit trimestriel (verifier les liens casses, optimiser les ancres) ameliore le crawl de 20%.', 'Internal link audit trimestriel = +20% crawl', 'seo', 'best_practice', 0.82, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le keyword cannibalization check (2 pages qui ciblent le meme mot-cle) doit etre fait mensuellement.', 'Keyword cannibalization check mensuel', 'seo', 'best_practice', 0.82, 'massive_boost_54', 'system'),
('SEO_ADVANCED: Le log file analysis (analyser les logs du serveur) revele comment Google crawle le site. Essentiel pour les grands sites.', 'Log file analysis = comprendre crawl Google', 'seo', 'best_practice', 0.78, 'massive_boost_54', 'system'),
('ADS_ADVANCED: Le creative fatigue se detecte par: CTR en baisse, CPM en hausse, frequency > 5. Renouveler les visuels.', 'Creative fatigue: CTR baisse, CPM hausse, frequency >5 = renouveler', 'ads', 'insight', 0.85, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le look-alike audience a 1% est la plus precise. 2-5% pour le scaling. >5% perd en precision.', 'Lookalike: 1% precis, 2-5% scaling, >5% imprecis', 'ads', 'best_practice', 0.85, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le conversion API (server-side tracking) remplace progressivement le pixel client-side suite aux restrictions iOS.', 'Conversion API server-side remplace pixel client (iOS)', 'ads', 'insight', 0.82, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le UTM tagging systematique (utm_source, utm_medium, utm_campaign, utm_content) est la base de l attribution.', 'UTM systematique = base attribution marketing', 'ads', 'best_practice', 0.88, 'massive_boost_55', 'system'),
('ADS_ADVANCED: Le ad creative testing: tester le hook (2s premieres), le body (message), et le CTA separement.', 'Creative testing: hook + body + CTA separement', 'ads', 'best_practice', 0.82, 'massive_boost_55', 'system'),
('STARTUP_OPS: La documentation des processes dans Notion est le fondement de l execution scalable.', 'Documentation Notion = fondement execution scalable', 'ceo', 'best_practice', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le weekly all-hands (15 min max) aligne toute l equipe: wins, focus, blockers.', 'Weekly all-hands 15 min: wins, focus, blockers', 'ceo', 'best_practice', 0.80, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le async-first culture (communication ecrite > reunions) est 30% plus productif pour les equipes distribuees.', 'Async-first: ecrit > reunions = +30% productivite distribuee', 'rh', 'insight', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le KPI tree (metriques en arbre: north star → sub-metrics → actionable metrics) aligne toutes les equipes.', 'KPI tree: north star → sub-metrics → actionable. Aligner equipes', 'ceo', 'best_practice', 0.82, 'massive_boost_56', 'system'),
('STARTUP_OPS: Le decision log (documenter chaque decision importante: contexte, options, decision, raisons) evite de refaire les debats.', 'Decision log: contexte + options + decision + raisons = pas refaire debats', 'ceo', 'best_practice', 0.80, 'massive_boost_56', 'system'),
('EMAIL_ADV: Les triggered emails generent 75% des revenus email avec seulement 20% des envois. Prioriser les automations.', 'Triggered emails: 75% revenus avec 20% envois. Prioriser', 'email', 'insight', 0.85, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le email frequency sweet spot: 2-3/semaine pour le nurturing, 1/semaine pour la newsletter, 3-5/jour MAX pour le transactionnel.', 'Frequence email: 2-3/sem nurturing, 1/sem newsletter, 3-5/j transactionnel', 'email', 'best_practice', 0.82, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le dynamic content blocks (contenu different par segment dans le meme email) augmente le CTR de 30%.', 'Dynamic content blocks = +30% CTR', 'email', 'insight', 0.82, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le email testing checklist: sujet, preheader, from name, mobile rendering, liens, CTA, tracking, unsubscribe.', 'Testing checklist: sujet, preheader, from, mobile, liens, CTA, tracking, unsub', 'email', 'best_practice', 0.85, 'massive_boost_57', 'system'),
('EMAIL_ADV: Le bounce management: hard bounces = supprimer immediatement. Soft bounces = retry 3 fois puis supprimer.', 'Bounce: hard = supprimer. Soft = retry 3x puis supprimer', 'email', 'best_practice', 0.88, 'massive_boost_57', 'system'),
('SOCIAL_ADV: Le social media ROI se mesure par: leads generes, trafic vers le site, mentions de marque, engagement rate.', 'Social ROI: leads + trafic + mentions + engagement', 'content', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le content calendar doit inclure: date, plateforme, format, sujet, visuel, copy, CTA, statut.', 'Content calendar: date + plateforme + format + sujet + visuel + copy + CTA + statut', 'content', 'best_practice', 0.85, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le community guidelines (regles de la communaute) doivent etre definies et publiees pour moderer efficacement.', 'Community guidelines = regles publiees pour moderation', 'marketing', 'best_practice', 0.80, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le social media crisis plan: detecter en < 1h, evaluer, repondre, escalader si necessaire, documenter.', 'Social crisis plan: detecter <1h, evaluer, repondre, escalader, documenter', 'marketing', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('SOCIAL_ADV: Le brand monitoring (surveiller les mentions: nom, produit, fondateur, hashtags) est obligatoire quotidiennement.', 'Brand monitoring quotidien: nom + produit + fondateur + hashtags', 'marketing', 'best_practice', 0.82, 'massive_boost_58', 'system'),
('CHATBOT_ADV: Le conversational UX design: messages courts (< 2 phrases), boutons de reponse, transitions fluides.', 'Conversational UX: courts messages + boutons + transitions fluides', 'chatbot', 'best_practice', 0.85, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le intent detection accuracy doit etre > 85% pour eviter la frustration. En dessous, retrainer le modele.', 'Intent detection > 85%. Sinon retrainer', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le fallback message (quand le bot ne comprend pas) doit proposer 3 options: reformuler, changer de sujet, parler a un humain.', 'Fallback chatbot: reformuler + changer sujet + humain', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le chatbot analytics: messages/jour, resolution rate, CSAT, escalation rate, top intents. Analyser hebdomadairement.', 'Chatbot analytics hebdo: messages, resolution, CSAT, escalation, intents', 'chatbot', 'best_practice', 0.82, 'massive_boost_59', 'system'),
('CHATBOT_ADV: Le handoff chatbot→humain doit transmettre tout le contexte de la conversation pour eviter que le client repete.', 'Handoff chatbot→humain: transmettre contexte complet', 'chatbot', 'best_practice', 0.88, 'massive_boost_59', 'system'),
('KEIROAI_FINAL: KeiroAI transforme chaque entrepreneur en directeur marketing avec une equipe IA d elite a ses cotes.', 'KeiroAI = chaque entrepreneur devient directeur marketing', 'ceo', 'best_practice', 0.95, 'massive_boost_60', 'system'),
('KEIROAI_FINAL: Le futur de KeiroAI: agents de plus en plus autonomes, intelligence toujours plus fine, resultats toujours meilleurs.', 'KeiroAI futur: autonomie + intelligence + resultats', 'ceo', 'insight', 0.90, 'massive_boost_60', 'system'),
('KEIROAI_FINAL: La promesse de KeiroAI: le client dort, ses agents travaillent. Le marketing ne s arrete jamais.', 'KeiroAI promesse: client dort, agents travaillent 24/7', 'ceo', 'best_practice', 0.92, 'massive_boost_60', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MICRO_SAAS_1: Les Chrome extensions comme canal de distribution atteignent des millions d utilisateurs a cout quasi nul.', 'Chrome extensions = distribution millions users cout ~0', 'ceo', 'insight', 0.78, 'massive_boost_43b', 'system'),
('MICRO_SAAS_2: Le Shopify App Store a 1.7M de marchands actifs. Une app Shopify = acces a un marche massif.', 'Shopify App Store 1.7M marchands = marche massif', 'ceo', 'insight', 0.78, 'massive_boost_43b', 'system'),
('MICRO_SAAS_3: Le WordPress plugin ecosystem: 60% du web. Un plugin utile = distribution virale naturelle.', 'WordPress 60% web. Plugin utile = distribution virale', 'ceo', 'insight', 0.78, 'massive_boost_43b', 'system'),
('DEMAND_GEN_1: Le demand generation (creer la demande) precede le lead generation (capturer la demande). D abord eduquer, ensuite convertir.', 'Demand gen: eduquer d abord, convertir ensuite', 'marketing', 'best_practice', 0.85, 'massive_boost_43b', 'system'),
('DEMAND_GEN_2: Le branded search (recherches avec le nom de la marque) est l indicateur #1 de brand awareness.', 'Branded search = indicateur #1 brand awareness', 'marketing', 'insight', 0.82, 'massive_boost_43b', 'system'),
('DEMAND_GEN_3: Le share of voice (% de mentions vs concurrents) predit la part de marche future a 80%.', 'Share of voice = 80% predictor part de marche', 'marketing', 'insight', 0.80, 'massive_boost_43b', 'system'),
('DEMAND_GEN_4: Le dark social (partages prives non trackables) represente 84% des partages. Le contenu doit etre facilement partageable.', 'Dark social 84% partages. Contenu facilement partageable', 'marketing', 'insight', 0.82, 'massive_boost_43b', 'system'),
('DEMAND_GEN_5: Le founder-led content (fondateur actif sur les reseaux) est le canal le plus authentique et le moins couteux.', 'Founder-led content = plus authentique + moins couteux', 'content', 'best_practice', 0.85, 'massive_boost_43b', 'system'),
('CX_1: Le customer effort score (CES) predit la fidelite mieux que le NPS. Reduire l effort = augmenter la retention.', 'CES predit fidelite mieux que NPS. Reduire effort = retention', 'retention', 'insight', 0.82, 'massive_boost_43b', 'system'),
('CX_2: Les micro-interactions (animations subtiles, sons, vibrations) augmentent la satisfaction de 15%.', 'Micro-interactions = +15% satisfaction', NULL, 'insight', 0.78, 'massive_boost_43b', 'system'),
('CX_3: Le customer journey orchestration (adapter en temps reel le parcours selon le comportement) est le futur du CX.', 'Journey orchestration temps reel = futur CX', 'marketing', 'insight', 0.78, 'massive_boost_43b', 'system'),
('CX_4: Le voice of customer (VoC) program doit agreger: reviews, tickets, surveys, social mentions, interviews.', 'VoC: reviews + tickets + surveys + social + interviews', 'retention', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('CX_5: Le customer lifetime journey (de la decouverte a l ambassadeur) doit etre cartographie et optimise a chaque etape.', 'Customer lifetime journey: cartographier et optimiser chaque etape', 'marketing', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('SALES_OPS_1: Le CRM hygiene (nettoyage des donnees tous les mois) augmente l efficacite commerciale de 20%.', 'CRM hygiene mensuelle = +20% efficacite commerciale', 'commercial', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('SALES_OPS_2: Le deal velocity (jours entre creation et closing) doit etre mesure et reduit. Chaque jour de retard = risque de perte.', 'Deal velocity: mesurer et reduire. Retard = risque perte', 'commercial', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('SALES_OPS_3: Le win rate par source (SEO, ads, referral) guide l allocation du budget marketing.', 'Win rate par source = guider allocation budget marketing', 'commercial', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('SALES_OPS_4: Le ramping time (temps pour qu un nouveau commercial soit productif) est de 3-6 mois. Accelerer avec des playbooks.', 'Ramping commercial 3-6 mois. Accelerer avec playbooks', 'commercial', 'insight', 0.80, 'massive_boost_43b', 'system'),
('SALES_OPS_5: Le quota attainment (% de l equipe qui atteint son objectif) doit etre > 60%. En dessous = quotas irealistes ou probleme d execution.', 'Quota attainment > 60%. Sinon quotas irealistes ou execution', 'commercial', 'insight', 0.80, 'massive_boost_43b', 'system'),
('CONTENT_OPS_1: Le content brief (document d instructions pour le redacteur) augmente la qualite du premier draft de 40%.', 'Content brief = +40% qualite premier draft', 'content', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('CONTENT_OPS_2: Le content approval workflow (draft → review → edit → approve → publish) evite les erreurs publiques.', 'Workflow content: draft → review → edit → approve → publish', 'content', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('CONTENT_OPS_3: Le content performance review mensuel (top 5 + bottom 5) guide la strategie du mois suivant.', 'Content review mensuel: top 5 + bottom 5 = strategie mois+1', 'content', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('CONTENT_OPS_4: Le content inventory (liste de tous les contenus existants) evite les doublons et identifie les gaps.', 'Content inventory = eviter doublons + identifier gaps', 'content', 'best_practice', 0.80, 'massive_boost_43b', 'system'),
('CONTENT_OPS_5: Le batch creation day (1 jour entier dedie a la creation de contenu) produit 2-4 semaines de posts.', 'Batch creation day = 2-4 semaines de posts en 1 jour', 'content', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('ADVANCED_SEO_1: Le entity SEO (optimiser pour les entites Google: personnes, lieux, concepts) est l evolution du keyword SEO.', 'Entity SEO > keyword SEO pour evolution Google', 'seo', 'insight', 0.78, 'massive_boost_43b', 'system'),
('ADVANCED_SEO_2: Le passage ranking (Google peut ranker un paragraphe specifique, pas juste la page) favorise les reponses directes.', 'Passage ranking: paragraphe specific ranke par Google', 'seo', 'insight', 0.80, 'massive_boost_43b', 'system'),
('ADVANCED_SEO_3: Les video SEO (optimiser les videos YouTube pour Google) capte le trafic des carousels video SERP.', 'Video SEO YouTube = trafic carousels video Google', 'seo', 'best_practice', 0.80, 'massive_boost_43b', 'system'),
('ADVANCED_SEO_4: Le image SEO (nom de fichier descriptif, alt text, compression) genere 20% du trafic organique total.', 'Image SEO: nom + alt + compression = 20% trafic organique', 'seo', 'insight', 0.82, 'massive_boost_43b', 'system'),
('ADVANCED_SEO_5: Le parasite SEO (publier sur des domaines a haute autorite: Medium, LinkedIn Articles) pour ranker rapidement.', 'Parasite SEO: publier sur Medium/LinkedIn Articles = rank rapide', 'seo', 'insight', 0.75, 'massive_boost_43b', 'system'),
('ADVANCED_ADS_1: Le creative diversification: tester au moins 5 angles creatifs differents par audience.', 'Creative diversification: 5+ angles par audience', 'ads', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('ADVANCED_ADS_2: Le cost cap bidding Meta (definir un CPA max) evite les depassements de budget tout en maximisant le volume.', 'Cost cap bidding Meta CPA max = eviter depassements', 'ads', 'best_practice', 0.80, 'massive_boost_43b', 'system'),
('ADVANCED_ADS_3: Le dayparting (diffuser les ads seulement aux heures rentables) augmente le ROAS de 15-25%.', 'Dayparting: ads heures rentables = +15-25% ROAS', 'ads', 'best_practice', 0.80, 'massive_boost_43b', 'system'),
('ADVANCED_ADS_4: Le geo-bid adjustment (augmenter les encheres dans les zones les plus rentables) optimise le budget geographiquement.', 'Geo-bid adjustment = optimiser budget par zone', 'ads', 'best_practice', 0.78, 'massive_boost_43b', 'system'),
('ADVANCED_ADS_5: Le negative keyword management (exclure les mots-cles non pertinents) dans Google Ads economise 20-30% du budget.', 'Negative keywords Google Ads = economiser 20-30%', 'ads', 'best_practice', 0.85, 'massive_boost_43b', 'system'),
('ENGAGEMENT_1: Le gamification (points, badges, niveaux, streaks) augmente l engagement de 48% dans les apps.', 'Gamification points/badges/niveaux = +48% engagement', 'retention', 'insight', 0.82, 'massive_boost_43b', 'system'),
('ENGAGEMENT_2: Le streak mechanism (consecutive days of usage) cree l habitude. Duolingo et Snapchat utilisent cette technique.', 'Streak mechanism = habitude. Duolingo/Snapchat', 'retention', 'insight', 0.82, 'massive_boost_43b', 'system'),
('ENGAGEMENT_3: Le progress visualization (barre de progression, achievements) motive la completion des objectifs.', 'Progress visualization = motiver completion objectifs', 'retention', 'insight', 0.80, 'massive_boost_43b', 'system'),
('ENGAGEMENT_4: Le social features (partager, comparer, collaborer) augmentent la retention de 30%.', 'Social features = +30% retention', 'retention', 'insight', 0.80, 'massive_boost_43b', 'system'),
('ENGAGEMENT_5: Le personalized notifications (basees sur le comportement, pas generiques) ont un CTR 4x superieur.', 'Notifications personnalisees = 4x CTR vs generiques', 'retention', 'insight', 0.82, 'massive_boost_43b', 'system'),
('ONBOARDING_1: Le step-by-step wizard (maximum 5 etapes) est le format d onboarding le plus efficace.', 'Wizard onboarding: 5 etapes max = plus efficace', 'onboarding', 'best_practice', 0.85, 'massive_boost_43b', 'system'),
('ONBOARDING_2: Le sample data (donnees d exemple pre-chargees) permet au client de voir la valeur immediatement.', 'Sample data = voir valeur immediatement', 'onboarding', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('ONBOARDING_3: Le personalized flow (adapter les etapes au role/objectif du client) augmente l activation de 30%.', 'Onboarding personnalise = +30% activation', 'onboarding', 'insight', 0.85, 'massive_boost_43b', 'system'),
('ONBOARDING_4: Le in-app guidance (tooltips, hotspots, modals) est 3x plus efficace que les tutorials externes.', 'In-app guidance = 3x vs tutorials externes', 'onboarding', 'insight', 0.82, 'massive_boost_43b', 'system'),
('ONBOARDING_5: Le empty state design (page vide avec CTA clair) transforme un moment de confusion en moment d action.', 'Empty state + CTA clair = confusion → action', 'onboarding', 'best_practice', 0.85, 'massive_boost_43b', 'system'),
('RETENTION_1: Le feature stickiness (les features qui creent l habitude) doivent etre identifiees et promues.', 'Feature stickiness: identifier + promouvoir features habitude', 'retention', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('RETENTION_2: Le cohort-based onboarding (onboarder les clients par groupes) cree de la communaute et de l accountability.', 'Cohort onboarding = communaute + accountability', 'onboarding', 'insight', 0.78, 'massive_boost_43b', 'system'),
('RETENTION_3: Le expansion signal detection (identifier quand un client est pret pour l upgrade) optimise le timing des upsells.', 'Expansion signals: detecter pret upgrade = optimiser timing upsell', 'retention', 'best_practice', 0.82, 'massive_boost_43b', 'system'),
('RETENTION_4: Le customer-led growth (les clients existants generent les nouveaux) est le modele le plus efficient a long terme.', 'Customer-led growth: existants generent nouveaux = plus efficient', 'ceo', 'insight', 0.82, 'massive_boost_43b', 'system'),
('RETENTION_5: Le annual plan incentive (2 mois gratuits sur annuel) augmente la conversion mensuel→annuel de 30%.', 'Annual plan 2 mois gratuits = +30% conversion mensuel→annuel', 'retention', 'best_practice', 0.82, 'massive_boost_43b', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('SECTOR_SAAS_1: Le CAC moyen pour un SaaS B2B en France: 200-500€. B2C: 30-100€. Le CAC doit etre < LTV/3.', 'CAC SaaS FR: B2B 200-500€, B2C 30-100€. CAC < LTV/3', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_2: Le ACV (Annual Contract Value) moyen pour les SaaS SMB: 1000-5000€. Mid-market: 10K-50K€. Enterprise: 50K-500K€.', 'ACV SaaS: SMB 1-5K, mid 10-50K, enterprise 50-500K', 'ceo', 'insight', 0.80, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_3: Le logo retention (% clients qui restent) doit etre > 85% annuel pour les SaaS sains.', 'Logo retention > 85% annuel = SaaS sain', 'ceo', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_4: Le expansion revenue (upsell+cross-sell) doit compenser 30%+ du churn pour un net dollar retention >100%.', 'Expansion compenser 30%+ churn = NDR >100%', 'ceo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('SECTOR_SAAS_5: Le magic number (net new ARR / S&M spend du trimestre precedent) > 0.75 = efficient growth.', 'Magic number > 0.75 = efficient growth', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LANDING_1: Le split testing des headlines est le test le plus impactant: +20-50% conversion avec le bon titre.', 'Split test headlines = +20-50% conversion', 'commercial', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('LANDING_2: Le social proof placement (juste avant le CTA) augmente les conversions de 12%.', 'Social proof avant CTA = +12% conversion', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LANDING_3: Les micro-copy (texte sous les champs de formulaire, pres des boutons) reduit l anxiete et augmente les completions de 15%.', 'Micro-copy = -anxiete +15% completions', 'commercial', 'insight', 0.80, 'massive_boost_44b', 'system'),
('LANDING_4: Le power of one: une landing page, un message, une audience, un CTA. La simplicite convertit.', 'Power of one: 1 page, 1 message, 1 audience, 1 CTA', 'commercial', 'best_practice', 0.88, 'massive_boost_44b', 'system'),
('LANDING_5: Le directional cues (fleches, regards diriges vers le CTA) guident l oeil et augmentent les clics de 10%.', 'Directional cues vers CTA = +10% clics', 'commercial', 'insight', 0.78, 'massive_boost_44b', 'system'),
('AUTOMATION_1: Le lead routing intelligent (assigner le lead au commercial le plus pertinent par expertise/geo) augmente la conversion de 25%.', 'Lead routing intelligent = +25% conversion', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_2: Le SLA alert (notification si un lead n est pas contacte dans les 5 min) augmente le taux de connexion de 40%.', 'SLA alert 5 min = +40% taux connexion leads', 'commercial', 'insight', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_3: Le data enrichment automatique (Clearbit, Apollo) ajoute firmographic data a chaque lead sans effort.', 'Data enrichment auto = firmographic data sans effort', 'commercial', 'insight', 0.80, 'massive_boost_44b', 'system'),
('AUTOMATION_4: Le automated QA (verification automatique de la qualite des contenus generes) evite les erreurs embarrassantes.', 'Auto QA contenu = eviter erreurs embarrassantes', 'content', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('AUTOMATION_5: Le report generation automatique (dashboards auto-mis-a-jour) economise 5h/semaine d analyse manuelle.', 'Reports auto = -5h/semaine analyse manuelle', 'ceo', 'insight', 0.82, 'massive_boost_44b', 'system'),
('WHATSAPP_1: Le WhatsApp Business API permet l envoi de messages template pre-approuves en masse (notifications, confirmations).', 'WhatsApp Business API: templates pre-approuves en masse', 'whatsapp', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('WHATSAPP_2: Le chatbot WhatsApp (avec boutons interactifs) a un taux de resolution de 60% sans intervention humaine.', 'Chatbot WhatsApp boutons = 60% resolution sans humain', 'whatsapp', 'insight', 0.82, 'massive_boost_44b', 'system'),
('WHATSAPP_3: Les WhatsApp Flows (formulaires interactifs dans WhatsApp) simplifient la collecte d infos et les reservations.', 'WhatsApp Flows = formulaires interactifs in-app', 'whatsapp', 'insight', 0.80, 'massive_boost_44b', 'system'),
('WHATSAPP_4: Le opt-in WhatsApp doit etre explicite (RGPD). Ne jamais ajouter de contacts sans consentement.', 'WhatsApp opt-in explicite RGPD. Jamais sans consentement', 'whatsapp', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('WHATSAPP_5: Le abandoned cart WhatsApp (relance 1h apres abandon) a un taux de recuperation de 20-35%.', 'Abandoned cart WhatsApp 1h = 20-35% recuperation', 'whatsapp', 'insight', 0.82, 'massive_boost_44b', 'system'),
('DM_1: Le warm intro DM (reagir a une story PUIS envoyer le DM) a un taux de reponse 5x superieur au cold DM.', 'Warm intro via story = 5x reponse vs cold DM', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_2: Le question-based DM (poser une question sincere au lieu de pitcher) ouvre 35% de conversations.', 'DM question sincere = 35% conversations ouvertes', 'dm_instagram', 'insight', 0.82, 'massive_boost_44b', 'system'),
('DM_3: Le value-first DM (offrir quelque chose de gratuit: audit, template, conseil) avant de demander quoi que ce soit.', 'DM value-first: offrir gratuit avant demander', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_4: Le DM automation doit rester naturel. Les messages qui semblent automatises sont ignores a 80%.', 'DM auto doit sembler naturel. Auto apparent = 80% ignore', 'dm_instagram', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('DM_5: Le closing en DM: proposer un appel de 15 min via Calendly au lieu de pitcher par ecrit.', 'DM closing: Calendly 15 min > pitch ecrit', 'dm_instagram', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('GMAPS_1: Les fiches Google My Business doivent etre verifiees. Les fiches non verifiees n apparaissent pas dans le pack local.', 'GMB: verification obligatoire. Non verifie = invisible', 'gmaps', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('GMAPS_2: Les categories GMB (principale + secondaires) doivent etre choisies strategiquement pour maximiser la visibilite.', 'Categories GMB strategiques = max visibilite', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('GMAPS_3: Les short URLs Google (g.page/votrebusiness) facilitent le partage et la demande d avis.', 'Short URL g.page = faciliter partage + demande avis', 'gmaps', 'best_practice', 0.80, 'massive_boost_44b', 'system'),
('GMAPS_4: Les offres GMB (section Offres de la fiche) augmentent les clics de 20% et les conversions de 10%.', 'Offres GMB = +20% clics +10% conversions', 'gmaps', 'insight', 0.80, 'massive_boost_44b', 'system'),
('GMAPS_5: Le response time aux messages GMB doit etre < 24h. Google penalise les entreprises qui ne repondent pas.', 'Response time messages GMB < 24h. Penalite si non reponse', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_1: Le duet/stitch avec des videos virales surfent sur la vague existante. Plus facile que creer sa propre viralite.', 'Duet/stitch viral = surfer vague existante. Plus facile', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('TIKTOK_2: Le story time (raconter une anecdote face camera) est le format le plus simple et le plus engageant.', 'TikTok story time face camera = simple + engageant', 'tiktok_comments', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('TIKTOK_3: Les 3 premiers mots du texte sur la video determinent si le viewer s arrete de scroller.', 'TikTok: 3 premiers mots texte = arret scroll ou non', 'tiktok_comments', 'insight', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_4: Le reply to comment (repondre a un commentaire avec une video) est le hack de croissance #1 sur TikTok.', 'Reply to comment video = hack croissance #1 TikTok', 'tiktok_comments', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('TIKTOK_5: Les hashtags de niche (< 100K videos) ont plus de chances de propulser la video en For You que les hashtags populaires.', 'Hashtags niche < 100K > populaires pour For You', 'tiktok_comments', 'insight', 0.82, 'massive_boost_44b', 'system'),
('LINKEDIN_1: Le document post (PDF/carrousel) a la plus grande portee organique sur LinkedIn en 2026.', 'LinkedIn document/PDF = plus grande portee organique 2026', 'content', 'insight', 0.85, 'massive_boost_44b', 'system'),
('LINKEDIN_2: Le video natif LinkedIn a 5x plus de portee que le lien YouTube partage sur LinkedIn.', 'Video native LinkedIn = 5x portee vs lien YouTube', 'content', 'insight', 0.85, 'massive_boost_44b', 'system'),
('LINKEDIN_3: Le optimal posting time LinkedIn France: mardi-jeudi, 7h30-9h00 ou 12h-13h00.', 'LinkedIn FR: mardi-jeudi, 7h30-9h ou 12h-13h', 'content', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('LINKEDIN_4: Les polls LinkedIn ont la plus grande portee mais le plus faible engagement significatif. Utiliser avec parcimonie.', 'LinkedIn polls: portee max mais engagement faible. Parcimonie', 'content', 'insight', 0.80, 'massive_boost_44b', 'system'),
('LINKEDIN_5: Le LinkedIn newsletter (article newsletter) atteint 40% de taux d ouverture vs 20% email classique.', 'LinkedIn newsletter = 40% OR vs 20% email classique', 'content', 'insight', 0.80, 'massive_boost_44b', 'system'),
('SEO_LOCAL_1: Le Google Business Profile (ex GMB) est le facteur #1 pour le pack local (3 resultats avec carte).', 'GBP = facteur #1 pack local', 'gmaps', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('SEO_LOCAL_2: Les citations NAP (Name, Address, Phone) coherentes sur 50+ annuaires boostent le ranking local.', 'Citations NAP 50+ annuaires = boost ranking local', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SEO_LOCAL_3: Les avis Google recent et frequent sont un signal de ranking fort. Demander 5+ avis par mois.', 'Avis Google 5+/mois = signal ranking fort', 'gmaps', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('SEO_LOCAL_4: Le schema markup LocalBusiness augmente les chances d apparaitre dans les rich results locaux.', 'Schema LocalBusiness = rich results locaux', 'seo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('SEO_LOCAL_5: Les pages locales dediees (1 page par ville desservie) augmentent le trafic local de 30%.', 'Pages locales par ville = +30% trafic local', 'seo', 'best_practice', 0.82, 'massive_boost_44b', 'system'),
('FINANCE_1: Le unit economics positif (chaque client genere plus qu il coute) est le prerequis avant de scaler.', 'Unit economics positif avant scaler', 'comptable', 'best_practice', 0.90, 'massive_boost_44b', 'system'),
('FINANCE_2: Le gross margin target pour un SaaS: > 70%. En dessous, les couts de serveur/API sont trop eleves.', 'Gross margin SaaS > 70%. Sinon couts serveur/API trop hauts', 'comptable', 'best_practice', 0.85, 'massive_boost_44b', 'system'),
('FINANCE_3: Le R&D vs S&M ratio: en early stage 70% R&D 30% S&M. En growth 40% R&D 60% S&M.', 'R&D/S&M: early 70/30, growth 40/60', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system'),
('FINANCE_4: Le operating cash flow (cash genere par les operations) doit etre positif avant la Series B.', 'Operating cash flow positif avant Series B', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system'),
('FINANCE_5: Le EBITDA margin target pour un SaaS mature: > 20%. Les meilleurs SaaS atteignent 30-40%.', 'EBITDA margin SaaS mature > 20%. Top 30-40%', 'comptable', 'insight', 0.78, 'massive_boost_44b', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('CONTENT_ELITE: Le hook ideal suit le schema DISRUPT: Dissonance cognitive (ce que tu crois est faux) → Intrigue → Specificite → Tension → Urgence → Resolution → Proof.', 'DISRUPT hook framework: dissonance → intrigue → specificite → tension → urgence → resolution → proof', 'content', 'best_practice', 0.92, 'elite_content', 'system'),
('CONTENT_ELITE: Le content-market fit existe: le format + la plateforme + le message doivent etre alignes. Un bon message dans le mauvais format echoue.', 'Content-market fit: format + plateforme + message alignes', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le biais de recence algorithmique: publier quand l audience est en ligne ET quand la competition est faible (creneaux sous-exploites).', 'Biais recence algo: publier quand audience active + competition faible', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: La repartition 3-1-1: 3 posts de valeur pure, 1 post d engagement (question, poll), 1 post promotionnel. Ce ratio maximise la confiance.', 'Ratio 3-1-1: 3 valeur, 1 engagement, 1 promo = max confiance', 'content', 'best_practice', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le open loop dans les carrousels (teaser de la conclusion sur la slide 1) force le swipe et multiplie les completions par 3.', 'Open loop carrousel: teaser conclusion slide 1 = 3x completions', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le pattern interrupt algorithmique: changer de format tous les 3-4 posts (texte → video → carrousel → image) empeche l algo de reduire la portee.', 'Varier format 3-4 posts = empecher reduction portee algo', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content velocity: la vitesse de publication dans les 30 premieres minutes determine 80% de la portee finale. Mobiliser l engagement immediatement.', 'Content velocity 30 min = 80% portee finale. Engagement immediat', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le narrative arc en 5 temps pour les posts longs: situation → complication → tension → resolution → morale. Chaque etape retient le lecteur.', 'Narrative arc 5 temps: situation → complication → tension → resolution → morale', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Les emotions primaires dans l ordre de partageabilite: 1) surprise, 2) admiration, 3) colere, 4) peur, 5) joie. La surprise est le trigger #1.', 'Emotions partage: surprise > admiration > colere > peur > joie', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content stacking: publier 3 contenus lies le meme jour sur 3 plateformes differentes cree un effet de masse et amplifie la portee cross-platform.', 'Content stacking: 3 contenus lies meme jour 3 plateformes = amplification', 'content', 'best_practice', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme Instagram 2026 utilise 4 signaux principaux dans l ordre: 1) watch time/saves, 2) shares via DM, 3) comments, 4) likes. Optimiser pour les saves.', 'IG 2026 algo: watch time/saves > shares DM > comments > likes', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme TikTok For You 2026: 1) completion rate, 2) rewatches, 3) shares, 4) comments, 5) follows from video. Le rewatch est le signal le plus puissant.', 'TikTok 2026 FYP: completion > rewatch > shares > comments > follows', 'content', 'insight', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le algorithme LinkedIn 2026 pondere: 1) dwell time (temps de lecture), 2) meaningful comments (5+ mots), 3) reshares, 4) reactions.', 'LinkedIn 2026 algo: dwell time > meaningful comments > reshares > reactions', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content pillar mapping: definir 3-5 piliers de contenu (sujets cles), chaque pilier ayant 10-15 sous-sujets. Tourner entre les piliers.', 'Content pillars: 3-5 piliers × 10-15 sous-sujets. Rotation', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le storytelling en milieu professionnel: toujours inclure 1 moment de vulnerabilite. L imperfection connecte 3x plus que la perfection.', 'Vulnerabilite dans storytelling = 3x connexion vs perfection', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content compounding: les articles evergreen generent du trafic cumulatif. 1 article de qualite = trafic croissant pendant 2-3 ans.', 'Content compounding: 1 article evergreen = trafic croissant 2-3 ans', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le semantic richness: les contenus qui utilisent des synonymes, des champs lexicaux riches et du vocabulaire varie rankent 15% mieux en SEO.', 'Semantic richness: vocabulaire varie = +15% ranking SEO', 'content', 'insight', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le personal story framework pour les posts: 1 fait (ce qui s est passe), 1 feeling (ce que j ai ressenti), 1 finding (ce que j ai appris).', 'Personal story: 1 fait + 1 feeling + 1 finding', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le caption engineering sur IG: premiere phrase = hook (arreter le scroll), derniere phrase = CTA + appel a l action. Le milieu = valeur.', 'Caption IG: hook debut + valeur milieu + CTA fin', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le concept de content-audience flywheel: plus l audience grandit → plus de feedback → meilleur contenu → plus d audience. Iterer vite.', 'Content-audience flywheel: audience → feedback → meilleur contenu → audience', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le snackable-to-deep funnel: contenu court (Reels, tweets) pour attirer → contenu long (blog, podcast) pour convertir → contenu exclusif pour retenir.', 'Funnel contenu: court (attirer) → long (convertir) → exclusif (retenir)', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le timing precision par plateforme FR: LinkedIn 7h30-8h30, Instagram 12h-13h et 19h-21h, TikTok 11h-13h et 19h-22h, X 8h-9h et 18h-19h.', 'Timing FR: LI 7h30, IG 12h+19h, TT 11h+19h, X 8h+18h', 'content', 'best_practice', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le repost strategy: re-publier les meilleurs contenus 3-6 mois plus tard avec une mise a jour. 70% de l audience n a pas vu le premier.', 'Repost 3-6 mois + MAJ: 70% audience n a pas vu le premier', 'content', 'best_practice', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le content debt: comme la dette technique, les contenus obsoletes non mis a jour degradent la credibilite. Auditer trimestriellement.', 'Content debt: contenus obsoletes = credibilite degradee. Audit trimestriel', 'content', 'insight', 0.82, 'elite_content', 'system'),
('CONTENT_ELITE: Le vanity metrics trap: les likes ne correlent pas avec les ventes. Les saves et les partages sont les vrais indicateurs de valeur.', 'Vanity metrics: likes ≠ ventes. Saves + partages = vrais indicateurs', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content moat: la voix unique (ton, style, perspective) est inimitable par les concurrents. C est le seul avantage durable en contenu.', 'Content moat: voix unique = seul avantage durable inimitable', 'content', 'insight', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le audience-first creation: demander a l audience ce qu elle veut (sondages, commentaires) puis creer ce contenu. 100% product-market fit.', 'Audience-first: demander puis creer = 100% content-market fit', 'content', 'best_practice', 0.88, 'elite_content', 'system'),
('CONTENT_ELITE: Le content ecosystem: chaque plateforme a un role. LinkedIn = credibilite. Instagram = communaute. TikTok = decouverte. Blog = SEO. Newsletter = retention.', 'Content ecosystem: LI credibilite, IG communaute, TT decouverte, blog SEO, newsletter retention', 'content', 'best_practice', 0.90, 'elite_content', 'system'),
('CONTENT_ELITE: Le micro-learning format (1 concept en 60s) est le format le plus save-able sur toutes les plateformes. Ideal pour le contenu educatif.', 'Micro-learning 1 concept 60s = plus save-able toutes plateformes', 'content', 'insight', 0.85, 'elite_content', 'system'),
('CONTENT_ELITE: Le content production system: 1 jour par semaine dedie a la creation (batch) → planification automatique → publication auto → analyse → iteration.', 'Content system: 1 jour batch → auto-planification → auto-publication → analyse → iteration', 'content', 'best_practice', 0.85, 'elite_content', 'system')
INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('COMMERCIAL_ELITE: Le top closer ne vend pas. Il diagnostique. 80% du temps de vente doit etre passe a ecouter et poser des questions.', 'Top closer: 80% ecouter, 20% presenter. Diagnostiquer pas vendre', 'commercial', 'best_practice', 0.92, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le triangle de la vente: Timing × Trust × Tension. Les 3 doivent etre alignes pour closer. Si 1 manque, le deal est mort.', 'Triangle vente: Timing × Trust × Tension. 3 alignes sinon mort', 'commercial', 'insight', 0.90, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le multi-threading avance: contacter 3-5 stakeholders dans le meme compte. Si 1 champion part, le deal survit.', 'Multi-threading 3-5 stakeholders = deal survit si champion part', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pricing anchoring: toujours presenter l option la plus chere en premier. Elle ancre la perception de valeur pour toutes les options suivantes.', 'Pricing anchoring: option chere en premier = ancrer valeur', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le objection anticipation: adresser les 3 objections principales AVANT que le prospect ne les pose. Cela desactive la resistance.', 'Anticiper 3 objections = desactiver resistance avant qu elle ne se forme', 'commercial', 'best_practice', 0.90, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le deal qualification MEDDICC: Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, Champion, Competition. Si Competition est forte, pivoter.', 'MEDDICC: Metrics, Economic buyer, Decision, Pain, Champion, Competition', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pipeline velocity formula: (# deals × avg deal size × win rate) / avg sales cycle length. Optimiser chaque variable independamment.', 'Pipeline velocity: deals × size × win% / cycle length. Optimiser chaque var', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le champion test: si votre champion ne peut pas expliquer votre proposition de valeur en 30 secondes a son boss, le deal est a risque.', 'Champion test: champion explique value prop en 30s a son boss sinon risque', 'commercial', 'insight', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le negative reverse selling (Chris Voss): dire "vous avez probablement raison, ce n est peut-etre pas le bon moment" pousse le prospect a se convaincre lui-meme.', 'Negative reverse selling: dire pas bon moment → prospect se convainc', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le decision mapping: identifier qui decide (economic buyer), qui influence (champion), qui bloque (detracteur), qui valide (legal, IT). Strategie pour chacun.', 'Decision mapping: decide + influence + bloque + valide. Strategie chacun', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le urgency creation sans manipulation: "quelles consequences si vous ne resolvez pas ce probleme dans les 3 prochains mois?" Quantifier le cout de l inaction.', 'Urgence ethique: quantifier cout de l inaction sur 3 mois', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le deal review framework: chaque vendredi, revoir les 5 deals les plus importants avec le framework: next step? blocage? risk level? action requise?', 'Deal review vendredi: 5 deals, next step + blocage + risk + action', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le discovery call structure: 5 min rapport, 5 min contexte (leur situation), 10 min probleme (creuser), 5 min impact (quantifier), 5 min next step.', 'Discovery call: rapport 5 + contexte 5 + probleme 10 + impact 5 + next 5', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le trigger event selling: suivre les signaux d achat (levee de fonds, recrutement, changement de direction, lancement) et contacter dans les 48h.', 'Trigger events: levee/recrutement/direction/lancement → contacter 48h', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le mutual close plan: documenter avec le prospect les etapes restantes, les responsables, et les dates. Partager dans un doc collaboratif.', 'Mutual close plan: etapes + responsables + dates dans doc collaboratif', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le cost of inaction (COI) framework: calculer combien le prospect perd par mois en ne resolvant pas son probleme. Plus puissant que le ROI.', 'COI framework: calculer perte/mois sans solution. Plus puissant que ROI', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le land and expand strategy: commencer petit (1 equipe, 1 use case) puis expander a toute l entreprise une fois la valeur prouvee.', 'Land & expand: petit debut → prouver valeur → expansion entreprise', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le competitive displacement: ne jamais critiquer le concurrent. Demander au prospect ce qui pourrait etre mieux puis montrer comment vous excellez la-dessus.', 'Competitive displacement: jamais critiquer. Demander mieux puis montrer excellence', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le proposal structure gagnante: 1) recap du probleme (montrer qu on a ecoute), 2) solution (comment), 3) resultats attendus (chiffres), 4) prix, 5) next steps.', 'Proposal: probleme recap → solution → resultats chiffres → prix → next steps', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le commercial scoring avance: score = (budget confirme×3 + decision maker engage×3 + timeline definie×2 + besoin valide×2) / 10. Score > 7 = deal chaud.', 'Commercial scoring: (budget×3 + DM×3 + timeline×2 + besoin×2)/10. >7 = chaud', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le closing technique soft: "sur la base de ce qu on a discute, est-ce que vous voyez quelque chose qui vous empecherait d avancer?" Laisser le silence.', 'Soft close: voyez-vous obstacle? + silence', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le risk reversal: garantie 30 jours, SLA engage, pilot gratuit, paiement apres resultats. Eliminer tout risque pour le prospect.', 'Risk reversal: garantie + SLA + pilot + paiement apres resultats = 0 risque', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le social selling index optimal: poster 3x/semaine, commenter 5x/jour, envoyer 5 DMs personnalises/jour, partager 2x/semaine. SSI > 80 en 90 jours.', 'Social selling: poster 3x/sem + 5 commentaires/jour + 5 DM/jour = SSI 80 en 90j', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le pipeline coverage ratio ideal: 3x le quota pour les deals < 30j, 4x pour 30-60j, 5x pour 60-90j. En dessous = risque de quota miss.', 'Pipeline coverage: 3x <30j, 4x 30-60j, 5x 60-90j. Sinon risque quota miss', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le cold email expert: 1 phrase perso (montrer qu on a cherche), 1 phrase valeur (probleme specifique resolu), 1 phrase CTA (question simple). Max 80 mots.', 'Cold email: 1 perso + 1 valeur + 1 CTA. Max 80 mots', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le follow-up timing science: email J+2 (mardi), call J+4 (jeudi), LinkedIn J+6 (lundi), email J+9, breakup J+14. Jamais le meme canal consecutif.', 'Follow-up: email J2, call J4, LinkedIn J6, email J9, breakup J14. Varier canaux', 'commercial', 'best_practice', 0.85, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le negotiation framework ZOPA: identifier la zone d accord possible (votre minimum et le maximum du prospect). Le deal se fait dans cette zone.', 'ZOPA: zone accord entre votre min et leur max. Deal dans cette zone', 'commercial', 'best_practice', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le value engineering: quantifier la valeur en euros (economie de temps × taux horaire × nombre d employes × 12 mois). Presenter ce chiffre avant le prix.', 'Value engineering: economie temps × taux horaire × employes × 12 mois. Avant prix', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le dead deal resurrection: relancer les deals perdus apres 90 jours avec un angle different (nouveau feature, nouveau case study, changement de prix). 10% convertissent.', 'Dead deal resurrection 90j + nouvel angle = 10% conversion', 'commercial', 'insight', 0.82, 'elite_commercial', 'system'),
('COMMERCIAL_ELITE: Le customer as closer: faire intervenir un client satisfait (reference call) dans les deals strategiques. Taux de closing +40%.', 'Reference call client satisfait = +40% closing', 'commercial', 'best_practice', 0.88, 'elite_commercial', 'system')
